// Marginalia curriculum — source of truth, ported verbatim from marginalia.html
// 30 days x 3 lessons (Sentence / Craft / Theory)

export type PracticeType = "diagnose" | "reflect" | "write" | "combine" | "rewrite";

export interface DiagnoseItem {
  sentence: string;
  options: string[];
  answer: number;
  explain: string;
}

export interface Practice {
  type: PracticeType;
  prompt: string;
  items?: DiagnoseItem[];
  options?: string[];
  profileKey?: string;
  rubric?: string;
}

export interface Lesson {
  track: "Sentence" | "Craft" | "Theory";
  source: string;
  title: string;
  body: string;
  keytakeaway: string;
  practice: Practice;
}

export interface CurriculumDay {
  day: number;
  theme: string;
  lessons: Lesson[];
}

export const CURRICULUM: CurriculumDay[] = [{"day":1,"theme":"What the sentence is really about","lessons":[{"track":"Sentence","source":"Sentence craft — the grammatical subject","title":"The noun you PICTURE vs. the noun the VERB grabs","body":"Here is the thing that trips most people up, and it is not a knowledge gap — it is a collision between two different meanings of 'subject.'\n\nWhen you read 'the box of nails,' your mind's eye lands on the NAILS. They are concrete, picturable, vivid — so they feel like what the sentence is about. That instinct is real. But it answers a different question than grammar is asking.\n\nThe grammatical subject is not 'what is most vivid.' It is a mechanical role: the noun the verb is making its statement about. Verbs do not reach for the most interesting noun — they reach for the one they are commenting on. Ask of 'The box of nails was heavy': what WAS heavy? The box was. The nails aren't doing the 'was heavy'; the box is. So 'box' is the subject, however boring it is, and however loudly the nails call for attention.\n\nWHY does the vivid noun keep stealing the role? Because English loves to name the plain, real subject and then hang a vivid detail off it inside an 'of' phrase: 'a bowl OF cherries,' 'the leader OF the rebels,' 'the smell OF roses.' The picturable thing gets tucked inside the describing phrase. And a noun inside a prepositional phrase ('of nails') can never be the subject — it already has a job, as the object of 'of,' and a word can only hold one grammatical job at a time. So it is disqualified, no matter how vivid.\n\nThe tool that beats the pull: don't ask 'what is this about?' (your eye says: nails). Point at the VERB and trace back to the noun it is actually describing. 'Was heavy' → the box. That noun is the subject. Do this enough times and the trace stops being a guess and becomes a glance — the same way sounding out c-a-t became just reading 'cat.' The guess-feeling burns off with reps; there is no ceiling.","keytakeaway":"The subject isn't the noun you can picture — it's the noun the verb is making its claim about. Point at the verb, trace back. The vivid noun is usually hiding in an 'of' phrase, disqualified.","practice":{"type":"diagnose","prompt":"For each sentence, the verb is in CAPS. Which noun is the verb making its claim about? (The vivid noun is often a decoy inside an 'of' phrase.)","items":[{"sentence":"The stack of dishes IS teetering on the edge.","options":["stack","dishes","edge"],"answer":0,"explain":"What IS teetering? The stack. 'Dishes' is inside 'of dishes' — object of 'of,' so disqualified, however picturable."},{"sentence":"A crowd of protesters WAS gathering downtown.","options":["crowd","protesters","downtown"],"answer":0,"explain":"What WAS gathering? The crowd. 'Protesters' is the vivid decoy inside the 'of' phrase — your eye grabs it, but the verb agrees with 'crowd' (singular: was)."},{"sentence":"The smell of roses FILLS the room.","options":["smell","roses","room"],"answer":0,"explain":"What FILLS the room? The smell. Roses are inside 'of roses' — disqualified. This is why it's 'fills' (singular), not 'fill.'"},{"sentence":"The list of demands WAS long.","options":["list","demands","none"],"answer":0,"explain":"What WAS long? The list. 'Demands' sits in the 'of' phrase. Note the agreement: 'list...was,' not 'demands...were.'"},{"sentence":"A box of old letters SITS in the attic.","options":["box","letters","attic"],"answer":0,"explain":"What SITS in the attic? The box. Letters are the vivid decoy; the box holds the subject role and the singular verb 'sits.'"},{"sentence":"The sound of the engines WAS deafening.","options":["sound","engines","none"],"answer":0,"explain":"What WAS deafening? The sound. 'Engines' is object of 'of' — disqualified. Hence 'sound...was.'"}]}},{"track":"Craft","source":"E.M. Forster, Aspects of the Novel","title":"Flat characters vs. round characters","body":"Forster gave us the most useful distinction in character-building. A FLAT character is built around a single idea or quality — summed up in one sentence, never surprising us. A ROUND character can surprise us convincingly; they contain contradiction and can change.\n\nFlat characters aren't bad writing — they're efficient, and a novel of nothing but round characters would exhaust you. The skill is knowing which to use where: your protagonist earns roundness; the innkeeper in one scene can stay flat and do his job. WHY it works: a reader's attention is finite, and roundness costs attention. Spend it where it matters.","keytakeaway":"Flat = one idea, never surprises. Round = contradictory, can surprise us. Roundness costs reader attention — spend it deliberately.","practice":{"type":"write","prompt":"Write two short descriptions of the SAME person — a barista. First make them flat (one dominant trait). Then round (introduce a genuine contradiction). 3-4 sentences each.","rubric":"The flat version should reduce the barista to a single clear quality; the round version should plant a contradiction that feels believable, not random."}},{"track":"Theory","source":"Auerbach, Mimesis","title":"Two ways of representing reality","body":"Auerbach opens Mimesis by contrasting two ancient styles. Homer describes everything in the bright foreground — nothing hidden, every object and feeling fully externalized. The Bible does the opposite: it is 'fraught with background,' full of the unsaid, the psychologically deep.\n\nThese are the two poles Western writing has swung between ever since. Do you put everything on the surface (clarity, fullness), or withhold and imply (depth, mystery)? Every scene you write leans one way, and knowing which — and why — is the beginning of style.","keytakeaway":"Homeric = everything on the surface. Biblical = fraught with background, meaning withheld. All prose lives between these poles.","practice":{"type":"reflect","prompt":"When you write a scene, which pull is stronger — explaining everything clearly (Homeric), or withholding and implying (Biblical)?","options":["I want everything clear and fully explained","I want to withhold, imply, leave gaps","It depends entirely on the scene","I honestly don't know yet"],"profileKey":"surface_vs_depth"}}]},{"day":2,"theme":"The load-bearing core","lessons":[{"track":"Sentence","source":"Sentence craft — the base clause","title":"Every sentence stands on one core: subject + verb","body":"Yesterday you learned to find the subject. Today: that subject, plus its verb, is the CORE of the sentence — the load-bearing wall. 'The dog barked.' Everything else in a longer sentence is an addition hung off that core.\n\nHere is the liberating part, and the WHY behind almost everything to come: long sentences do not work by being more complicated at the center. They work by keeping ONE clear core and attaching extra material around it. 'The dog barked at the mailman all afternoon, hoarse by dinnertime, ignored by everyone' — still one core ('the dog barked'), just with additions. Strip the additions and a clean statement remains.\n\nWHY this matters to you specifically: sentences that 'pile up and bury the point' have almost always lost their core, or grown a second one that fights the first. When a sentence feels like a heap, the fix is not to add commas — it is to find the single core and make sure everything else is clearly SUBORDINATE to it, hanging off it rather than competing with it.\n\nSo the first move in building OR fixing any sentence is the same: locate (or decide) the one core. What is this sentence really claiming — one subject, one verb? Get that solid, in three or four words, and you have a wall you can build on. Try to build without it and you get a pile.","keytakeaway":"Every sentence stands on one core (subject + verb). Long sentences keep one clear core and hang additions off it. A sentence that 'piles up' has lost its core or grown a competing one.","practice":{"type":"diagnose","prompt":"Each sentence has additions hung around a single core. The verb is in CAPS. Which two- or three-word phrase is the core (subject + verb)?","items":[{"sentence":"After the storm, the old oak by the fence FELL across the road.","options":["the oak fell","the storm fell","the fence fell"],"answer":0,"explain":"Strip the additions ('after the storm,' 'by the fence,' 'across the road') and the core is 'the oak fell.' Everything else locates or times it."},{"sentence":"Exhausted and soaked, the runners FINISHED well after dark.","options":["the runners finished","exhausted finished","the dark finished"],"answer":0,"explain":"'Exhausted and soaked' describes the runners; 'well after dark' times the finish. Core: 'the runners finished.'"},{"sentence":"In the corner of the crowded room, a single candle BURNED.","options":["a candle burned","the room burned","the corner burned"],"answer":0,"explain":"The place-phrases ('in the corner,' 'of the crowded room') set the scene. Core: 'a candle burned.'"},{"sentence":"Whispering to no one in particular, she TURNED the page.","options":["she turned","whispering turned","no one turned"],"answer":0,"explain":"'Whispering to no one in particular' is an added modifier describing her. Core: 'she turned.'"},{"sentence":"The report, dense with numbers and hedged at every turn, CONVINCED nobody.","options":["the report convinced","numbers convinced","every turn convinced"],"answer":0,"explain":"The stuff between the commas describes the report. Core: 'the report convinced' (nobody)."}]}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"Free indirect style","body":"The single most powerful tool in modern fiction, and most readers never notice it. Free indirect style blends the narrator's third-person voice with a character's thoughts, without quotation marks or 'he thought.'\n\nCompare 'He looked at the sea. He thought: it is grey and cold' (clunky, tagged) with 'He looked at the sea. It was grey and cold, and he hated it' — that last clause is HIS judgment, delivered in the narrator's voice. WHY it's powerful: it gives you the intimacy of first person (we're inside him) with the freedom of third (the narrator can still move, describe, judge). No machinery, no 'he thought' — the membrane between narrator and character goes transparent.","keytakeaway":"Free indirect style = character's thoughts in the narrator's third-person voice, no tags. Intimacy of first person, freedom of third.","practice":{"type":"rewrite","prompt":"Rewrite using free indirect style: 'Maria stared at the letter. She thought to herself, this cannot be happening.'","rubric":"A strong answer drops 'she thought to herself' and folds the judgment into the narration, e.g. 'Maria stared at the letter. This could not be happening.'"}},{"track":"Theory","source":"Barthes, The Death of the Author","title":"The reader makes the meaning","body":"Barthes' 1967 essay detonated an old assumption: that to understand a text you find what the author 'meant.' He argued the opposite — a text's unity lies not in its origin (the author) but in its destination (the reader).\n\nOnce written, the work is cut loose from the writer's intentions; meaning is produced by whoever reads it. This is liberating for you: you don't control the final meaning, and you can't. Your job is to build a rich, open structure — the reader brings it to life. It also frees you from 'what did I really mean here?' Sometimes the text knows more than you did.","keytakeaway":"Meaning lives in the reader, not the author's intentions. You build the structure; readers complete it.","practice":{"type":"reflect","prompt":"How much do you WANT to control what a reader takes from your writing?","options":["Totally — I want them to get exactly what I meant","Mostly — but some room to interpret is fine","Loosely — I like when readers find things I didn't plan","I want the text to fully escape me"],"profileKey":"control_vs_openness"}}]},{"day":3,"theme":"Agreement and the hidden subject","lessons":[{"track":"Sentence","source":"Sentence craft — subject-verb agreement","title":"Why the verb agrees with the true subject, not the nearest noun","body":"Now that you can find the true subject, agreement stops being a rule to memorize and becomes something you can DERIVE.\n\nThe principle: a verb makes a statement about ONE thing — its subject — so it takes the number (singular/plural) of that thing. 'The box was heavy' (one box, singular verb). The verb and its subject are a matched pair; the verb is just echoing how many the subject is.\n\nWHY it goes wrong: English usually parks the subject right next to the verb, so your ear is trained to grab the nearest noun and match to THAT. When a phrase wanders in between — 'the box OF NAILS was heavy' — the nearest noun ('nails') is the wrong one, but your ear reaches for it anyway and wants 'were.' The rule exists purely to override that misleading proximity. Once you trace the verb back to its real subject (yesterday's move), agreement takes care of itself: 'nails' was never eligible, so plural never had a claim.\n\nThe usual traps, all the same mechanism — a decoy noun sitting between subject and verb:\n• 'of' phrases: 'The list of demands WAS long.' (list, not demands)\n• 'as well as / along with / together with': these are NOT 'and.' 'The captain, as well as the sailors, WAS rescued.' WHY: only 'and' actually adds people to the subject; 'as well as' is a side comment, an aside, so the subject stays just 'the captain.'\n• 'each / either / neither / one of': all singular. WHY: they point to ONE at a time. 'Each of the players IS ready' — 'each' means one-by-one, so singular.","keytakeaway":"The verb echoes the NUMBER of its true subject. Agreement errors happen when a decoy noun sits between subject and verb and your ear grabs it. 'As well as' isn't 'and'; 'each/either/neither' point to one, so they're singular.","practice":{"type":"diagnose","prompt":"Pick the correct verb. (Trace it back to the true subject first — ignore the decoy noun sitting in between.)","items":[{"sentence":"Neither of the answers ___ correct.","options":["is","are"],"answer":0,"explain":"'Neither' points to one at a time — singular. 'Answers' is a decoy in the 'of' phrase. So: 'Neither... is.'"},{"sentence":"The captain, as well as the sailors, ___ rescued.","options":["was","were"],"answer":0,"explain":"'As well as' is an aside, not 'and' — it doesn't add to the subject. The subject is just 'the captain': 'was rescued.'"},{"sentence":"Each of the houses on the street ___ a red door.","options":["has","have"],"answer":0,"explain":"'Each' means one-by-one — singular. 'Houses' is the decoy. 'Each... has.'"},{"sentence":"The box of old tools ___ in the shed.","options":["is","are"],"answer":0,"explain":"True subject is 'box' (singular); 'tools' is object of 'of.' 'The box... is.'"},{"sentence":"The manager, together with her assistants, ___ attending.","options":["is","are"],"answer":0,"explain":"'Together with' is an aside, not 'and.' Subject is 'the manager': 'is attending.'"},{"sentence":"One of my friends ___ moving to Berlin.","options":["is","are"],"answer":0,"explain":"'One' is the subject — singular. 'Of my friends' is the decoy phrase. 'One... is.'"}]}},{"track":"Craft","source":"Shklovsky, On the Theory of Prose","title":"Defamiliarization (ostranenie)","body":"Shklovsky argued that art exists to make us SEE again. Habit deadens perception — we stop noticing the stone, the sea, our own hand. Art's job is to 'make the stone stony': slow perception down and strip away the automatic.\n\nWHY it works: recognition is fast and shallow — we label a thing ('a sunset') and move on without really seeing it. Defamiliarization refuses the ready-made label, forcing the reader to actually perceive. Tolstoy describes a church service or a horse's life as if for the first time, with no name for it, and it becomes strange and vivid. Take a cliché (falling in love, a sunset) and describe it as if you'd never met the concept.","keytakeaway":"Defamiliarization = describe the familiar as if strange and new. Recognition is shallow; refusing the ready-made label forces real perception.","practice":{"type":"write","prompt":"Describe an ordinary act — brushing your teeth — using defamiliarization. Refuse every familiar word for it. Make the reader see it fresh and strange. 3-5 sentences.","rubric":"Avoid the obvious vocabulary ('toothbrush,' 'brush,' 'teeth'); render the act as if observed by someone with no concept of it — foam, bristles, ritual, repetition."}},{"track":"Theory","source":"Auerbach, Mimesis (cont.)","title":"The mixing of high and low","body":"One of Auerbach's great themes is the breaking of the 'separation of styles.' In classical antiquity, elevated subjects (heroes, gods, tragedy) demanded elevated language, and everyday or low subjects got low language — the two never mixed.\n\nChristianity shattered this: a carpenter's son as the most serious figure imaginable forced high seriousness into ordinary, humble life. The modern novel inherits this freedom — it can treat a housewife's afternoon with the gravity once reserved for kings. When you grant deep seriousness to a small, ordinary moment, you're using a technique that took Western literature a thousand years to unlock.","keytakeaway":"The novel can treat ordinary, humble life with full seriousness — a hard-won freedom. Small moments can carry great weight.","practice":{"type":"reflect","prompt":"What subject matter pulls at you as a writer?","options":["Big, elevated, dramatic subjects","Small, ordinary, domestic moments","The clash of both in one scene","I want to make the tiny feel enormous"],"profileKey":"high_vs_low"}}]},{"day":4,"theme":"Building outward: the cumulative sentence","lessons":[{"track":"Sentence","source":"Francis Christensen, cumulative sentence","title":"Add AFTER the base — and why that's easy to read","body":"This is the single most useful pattern for choppy writing, and it directly fixes 'my sentences are correct but I can't combine them.'\n\nThe move: write your base clause (the core from Day 2), then keep adding modifying phrases ONTO THE END. Each addition gives a detail, an image, a consequence. The sentence grows rightward while the core stays put at the front.\n\n'She stood at the window, coffee cooling in her hand, watching the street fill with rain, thinking of nothing at all.'\nBase: 'She stood at the window.' Everything after the first comma is a free modifier, added on.\n\nWHY it reads so easily — this is the important part: the reader meets the CORE THOUGHT FIRST, then receives each detail as an elaboration of something they already understand. Their mind has a hook to hang each new phrase on. Compare front-loading the modifiers ('Coffee cooling in her hand, watching the street fill with rain, thinking of nothing, she stood at the window') — now the reader must hold a pile of loose details in memory with nothing to attach them to, waiting for the core to arrive and rescue them. The cumulative sentence never makes the reader wait. It's how you combine four choppy little sentences into one flowing one WITHOUT burying the point — because the point came first.\n\nThe most common free-modifier shapes:\n• -ing phrase: '...watching the rain'\n• -ed phrase: '...exhausted by the climb'\n• noun phrase (appositive): '...a small, stubborn woman'\n• adjective phrase: '...pale in the lamplight'","keytakeaway":"Cumulative sentence: base clause first, then pile on free modifiers (-ing, -ed, noun, adjective phrases). It reads easily because the reader gets the core to hang details on BEFORE the details arrive — never made to wait.","practice":{"type":"combine","prompt":"Combine each set of choppy sentences into ONE cumulative sentence — base clause first, then the rest as free modifiers hung on the end. Do all three.\n\n1. The cat sat on the fence. It watched the birds. Its tail twitched.\n2. The old man walked to the pier. He was leaning on a cane. He was humming an old song.\n3. She opened the letter. Her hands were shaking. She was already crying.","rubric":"Each answer should lead with a clear base clause, then add the rest as free modifiers (often -ing or -ed phrases) after it — not glued with 'and,' and not front-loaded before the core. e.g. 'The cat sat on the fence, watching the birds, its tail twitching.'"}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"The telling detail","body":"Wood loves the detail that does disproportionate work — the small, concrete, slightly irrelevant-seeming thing that makes a scene suddenly real. Not a pile of description, but one precise, chosen detail. He calls the best of these 'lifeness.'\n\nA character isn't 'sad'; she 'keeps the dead man's voicemail and lets the mailbox fill.' WHY one detail beats many: a specific, slightly odd detail feels OBSERVED rather than invented, and the reader's mind fills in the rest — a pile of generic detail feels manufactured and gives the imagination nothing to do. Cut generic detail ruthlessly; protect the one strange specific that could only belong to this person, this moment.","keytakeaway":"One precise, slightly odd concrete detail beats a paragraph of generic description — it feels observed, and the reader completes it.","practice":{"type":"write","prompt":"Show that a character is grieving WITHOUT using the words sad, grief, cry, or loss — using one or two telling physical details. 2-3 sentences.","rubric":"Convey grief through a concrete, specific, observed detail (an object, a habit, a small action) rather than naming the emotion."}},{"track":"Theory","source":"Foucault, What Is an Author?","title":"The author-function","body":"Foucault picked up where Barthes left off, but complicated it. He asked: what does the author's NAME actually do? 'Shakespeare' isn't just a dead man — it's a function that organizes how we read, classifies texts, gives them status, tells us how to interpret. He called this the 'author-function.'\n\nNotice we don't attach it to everything: a private letter has a writer but no 'author' in this sense; a laundry list has a maker but no author-function. The concept matters because it reveals that 'being an author' is a role society constructs, not just the act of writing. What you write becomes 'literature' partly through forces outside the text.","keytakeaway":"The 'author-function' is a role society constructs around a name — it organizes how texts are read and valued, beyond the writing itself.","practice":{"type":"reflect","prompt":"Do you write toward being 'an author' (a public role), or toward the private act of writing itself?","options":["I want the public role — to be read as an Author","I care about the act of writing, not the title","Both pull at me equally","I'm still figuring out why I write at all"],"profileKey":"public_vs_private_writer"}}]},{"day":5,"theme":"Building for suspense: the periodic sentence","lessons":[{"track":"Sentence","source":"Sentence craft — the periodic sentence","title":"Modifiers FIRST, main clause LAST — and why it grips","body":"The periodic sentence is the mirror image of the cumulative one, and it is your tool for CONTROLLING EMPHASIS — your third pain point.\n\nThe move: hold the additions at the front and delay the main clause to the very end. 'Cold, exhausted, and certain now that no one was coming, she turned back.' The core ('she turned back') lands last.\n\nWHY it creates suspense and emphasis: a sentence isn't fully resolved in the reader's mind until the main clause arrives. Delay that clause, and you hold the reader in tension — they have the setup but not the payoff, so they lean forward. Then the core lands with the full weight of everything that preceded it. The final position is the strongest spot in any sentence (more on Day 14), and the periodic sentence weaponizes it.\n\nContrast the two patterns and WHEN to use each:\n• CUMULATIVE (core first, then additions) = relaxed, flowing, easy — the reader is never in suspense. Use for description, momentum, accumulation.\n• PERIODIC (additions first, core last) = tense, emphatic, controlled — the reader waits for the payoff. Use when you want a point to LAND hard, at the end.\n\nThis is the direct answer to 'the important idea ends up in the wrong place.' If your key idea is getting buried mid-sentence, a periodic structure moves it to the emphatic final position ON PURPOSE. You're not at the mercy of where the idea fell — you decide where it lands by choosing the pattern.","keytakeaway":"Periodic sentence: additions first, main clause LAST. It grips because the reader isn't resolved until the core arrives — so delaying it builds tension and lands the point hard. Use it to force your key idea into the emphatic final position.","practice":{"type":"combine","prompt":"Rewrite each as a PERIODIC sentence — delay the main clause to the end so the key idea lands last. Do all three.\n\n1. She finally understood the truth after years of doubt, sleepless nights, and one last betrayal.\n2. The bridge collapsed, despite every warning, every inspection, and every promise it was safe.\n3. He said yes, knowing the cost, knowing his family would object, knowing there was no going back.","rubric":"Each answer should front-load the modifiers/subordinate material and place the main clause at the very end, so the key idea occupies the emphatic final position. e.g. 'After years of doubt, sleepless nights, and one last betrayal, she finally understood the truth.'"}},{"track":"Craft","source":"Peter Brooks, Reading for the Plot","title":"Desire is the motor of narrative","body":"Brooks' central idea: what drives a plot forward is DESIRE — a wanting that won't be satisfied until the end. Narrative is fundamentally about a lack, a want, an ambition that pulls us (and the character) through time toward resolution.\n\nWHY 'and then, and then' isn't a plot: events alone are inert — nothing makes us NEED the next one. A governing desire organizes the events and gives them direction; we keep reading because we, like the protagonist, want something. Before you plot a story, ask the Brooks question: what does this narrative WANT? What is the engine of wanting that carries a reader to the last page?","keytakeaway":"Plot runs on desire — a governing want that pulls character and reader toward the end. Events without desire are inert.","practice":{"type":"write","prompt":"State the central DESIRE that would drive a story you'd want to write — not the plot, the wanting underneath it. Then name what stands in its way.","rubric":"Name a clear, specific desire (not a vague theme) and an obstacle, showing that desire + resistance generates narrative momentum."}},{"track":"Theory","source":"Virginia Woolf, A Room of One's Own","title":"The material conditions of writing","body":"Woolf's famous claim — 'a woman must have money and a room of her own if she is to write fiction' — is not just about women. It's a profound argument that art depends on material conditions: time, space, money, freedom from interruption.\n\nGenius doesn't float free of circumstance; it needs conditions to grow. Her invented 'Judith Shakespeare' — Shakespeare's equally gifted sister who could never write because society gave her no room — dramatizes how much talent has been silenced by lack of means. For you: your writing life isn't only about inspiration or discipline; it's about honestly securing the conditions that make the work possible.","keytakeaway":"Writing needs material conditions — time, space, money, freedom. Talent alone isn't enough; it needs room to grow.","practice":{"type":"reflect","prompt":"What is the biggest thing standing between you and a steadier writing practice?","options":["Time — I can't protect enough of it","Space — no room of my own, literal or mental","Confidence — I doubt the work is worth it","Direction — I don't know what I'm trying to write"],"profileKey":"biggest_obstacle"}}]},{"day":6,"theme":"Where you attach: branching","lessons":[{"track":"Sentence","source":"Sentence craft — left/mid/right branching","title":"Three places to attach a modifier, and what each does","body":"You now have two patterns (cumulative, periodic). Underneath both is a single idea: a modifier can attach in one of three places relative to the core. Knowing them by name lets you place any addition deliberately.\n\nTake the core: 'The dog barked.'\n\n• LEFT-branching (before the core): 'Frightened by the thunder, the dog barked.' The addition comes first. WHY/effect: it makes the reader wait for the core (mild suspense) and sets a condition before we meet the subject. A little goes a long way — too much left-branching and the reader is holding details with no anchor (the periodic risk).\n\n• MID-branching (inside the core, interrupting): 'The dog, frightened by the thunder, barked.' The addition splits subject from verb. WHY/effect: it inserts information right where it's relevant, but it DELAYS the verb, so long mid-branches strain the reader's memory — they're holding 'the dog...' open, waiting for what it does. Keep mid-branch interruptions short.\n\n• RIGHT-branching (after the core): 'The dog barked, frightened by the thunder.' The core lands first, additions trail after. WHY/effect: easiest to read (it's the cumulative pattern) — the reader is never left waiting.\n\nThe practical rule this gives you: English reads most easily when it branches RIGHT. Left- and mid-branching are powerful for emphasis and variety, but each one asks the reader to hold something open. That 'holding open' is exactly why heavily front-loaded or interrupted sentences feel like they 'pile up.' When a sentence of yours feels congested, the fix is often to move a modifier from the left or middle to the RIGHT.","keytakeaway":"A modifier attaches left (before core), mid (interrupting core), or right (after core). Right-branching reads easiest — the reader never waits. Left/mid branching add emphasis but make the reader hold something open, which is why front-loaded sentences feel congested.","practice":{"type":"diagnose","prompt":"For each sentence, where is the main modifier attached relative to the core clause?","items":[{"sentence":"Trembling and pale, the witness took the stand.","options":["left-branching (before core)","mid-branching (interrupting)","right-branching (after core)"],"answer":0,"explain":"'Trembling and pale' comes BEFORE the core 'the witness took the stand' — left-branching. The reader waits for the subject."},{"sentence":"The witness, trembling and pale, took the stand.","options":["left-branching (before core)","mid-branching (interrupting)","right-branching (after core)"],"answer":1,"explain":"The modifier splits the subject ('the witness') from the verb ('took') — mid-branching. It delays the verb."},{"sentence":"The witness took the stand, trembling and pale.","options":["left-branching (before core)","mid-branching (interrupting)","right-branching (after core)"],"answer":2,"explain":"Core first ('the witness took the stand'), modifier trails after — right-branching. Easiest to read."},{"sentence":"Because the road was flooded, we turned back.","options":["left-branching (before core)","mid-branching (interrupting)","right-branching (after core)"],"answer":0,"explain":"The subordinate clause comes before the core 'we turned back' — left-branching."},{"sentence":"We turned back because the road was flooded.","options":["left-branching (before core)","mid-branching (interrupting)","right-branching (after core)"],"answer":2,"explain":"Core first, reason trailing after — right-branching. The reader gets the main action before the explanation."}]}},{"track":"Craft","source":"E.M. Forster, Aspects of the Novel","title":"Story vs. plot","body":"Forster's razor-sharp distinction: 'The king died and then the queen died' is a STORY — events in time sequence. 'The king died, and then the queen died of grief' is a PLOT — events bound by causality.\n\nStory appeals to curiosity ('and then?'); plot appeals to intelligence and memory ('why?'). WHY causation grips and sequence bores: causality asks the reader to hold events together and see how they produce one another — it engages the mind, not just the appetite for what's next. When you revise, look at your string of events and ask: do these just happen in order, or does each CAUSE the next? Turning 'and then' into 'because' is often the whole job of revision.","keytakeaway":"Story = 'and then' (sequence). Plot = 'because' (causality). Causation engages the mind; sequence merely passes.","practice":{"type":"rewrite","prompt":"Turn this story into a plot by adding causality: 'She quit her job. She moved to Lisbon. She started painting.'","rubric":"Link the events causally (each one because of the last) rather than leaving them as a sequence of unrelated happenings."}},{"track":"Theory","source":"Eagleton, Marxism and Literary Criticism","title":"Literature doesn't float free of its world","body":"Eagleton's accessible entry into Marxist criticism makes one core move: literature is not produced in a vacuum. A text is shaped by the material and social conditions of its moment — who had power, who had money, whose labor was invisible.\n\nThis doesn't reduce art to propaganda; it means every work carries the fingerprints of its historical situation, often in what it leaves out or takes for granted. A Jane Austen novel assumes a whole economic order in its silences about where the money comes from. As a writer, this is a lens on your own work: what does your writing quietly assume about class, work, and money — and whose perspective does it leave out?","keytakeaway":"Texts are shaped by their material/social conditions — including in their silences. Ask what your writing takes for granted.","practice":{"type":"reflect","prompt":"How conscious are you of class, money, and work in what you write?","options":["Very — it's central to my interests","Somewhat — it's in the background","Rarely — I focus on the inner/personal","I hadn't thought about it as material for writing"],"profileKey":"social_awareness"}}]},{"day":7,"theme":"Joining equals: coordination","lessons":[{"track":"Sentence","source":"Sentence craft — coordination","title":"Joining equal ideas — the direct cure for choppiness","body":"Coordination is how you join elements of EQUAL grammatical weight: two words, two phrases, or two whole clauses. The coordinating conjunctions are the FANBOYS: For, And, Nor, But, Or, Yet, So.\n\nThis is the first real cure for choppy writing. 'I woke up. I made coffee. I read the news.' — three equal little clauses, machine-gun rhythm. Coordinate them: 'I woke up, made coffee, and read the news.' One sentence, same three actions, but now they flow as a set.\n\nWHY coordination specifically (versus just combining): it signals to the reader that the joined things are PEERS — equal in importance, part of one series or one balanced pair. 'She was tired but happy' tells the reader these two states matter equally and sit in tension. That's information the reader gets from the STRUCTURE, before they even weigh the words.\n\nThe key mechanical point — and the WHY behind the comma rule you half-know: when 'and/but/or' joins two FULL independent clauses (each could be its own sentence), you put a comma before it, because you're joining two complete units and the comma marks the seam: 'The sun set, and the air turned cold.' But when it just joins two verbs sharing one subject, there's no second complete unit, so no comma: 'The sun set and cooled the air.' The comma isn't decoration — it's a signal of how many complete clauses you're welding together. No second subject, no seam, no comma.\n\nThe danger (Day 18 revisits this): coordinating EVERYTHING with 'and...and...and' makes all ideas seem equal, which flattens emphasis. Coordination is for genuine peers. When ideas AREN'T equal, you need the opposite tool — subordination (tomorrow).","keytakeaway":"Coordination (FANBOYS) joins EQUAL elements and signals they're peers. Comma before and/but/or only when a full second clause follows — the comma marks the seam between two complete units. Coordinating unequal ideas flattens emphasis.","practice":{"type":"diagnose","prompt":"Does the sentence need a comma before the conjunction? (Ask: is there a FULL second clause — its own subject and verb — after it?)","items":[{"sentence":"She packed her bags ___ left before dawn.","options":["comma before 'and'","no comma"],"answer":1,"explain":"'left before dawn' shares the subject 'she' — no second subject, no complete second clause, no seam. So no comma."},{"sentence":"The sun set ___ and the air turned cold.","options":["comma before 'and'","no comma"],"answer":0,"explain":"'the air turned cold' is a full clause with its own subject — two complete units, so a comma marks the seam."},{"sentence":"He studied for weeks ___ but he still felt unready.","options":["comma before 'but'","no comma"],"answer":0,"explain":"'he still felt unready' is a full independent clause — comma before 'but.'"},{"sentence":"I opened the door ___ and looked inside.","options":["comma before 'and'","no comma"],"answer":1,"explain":"'looked inside' shares the subject 'I' — just a second verb, no new clause. No comma."},{"sentence":"We can leave now ___ or we can wait for the rain to stop.","options":["comma before 'or'","no comma"],"answer":0,"explain":"'we can wait...' is a full clause with its own subject — comma before 'or.'"}]}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"Point of view and a character's 'this-ness'","body":"Wood argues that great fiction convinces us of a character's separate consciousness — their particular way of noticing the world. In a character's point of view, the DETAILS they notice should be theirs, colored by who they are.\n\nA soldier and a florist walk through the same garden and see different things. WHY this matters: weak POV describes a neutral, camera-like world that could belong to anyone; strong POV lets the SEEING itself characterize, so description does double duty — it renders the world AND the mind perceiving it. When you write a scene, ask: whose eyes are these? What would THIS person, with this history and these hungers, notice first?","keytakeaway":"Strong point of view = the details noticed are shaped by the noticing mind. Description then does double duty: world plus perceiver.","practice":{"type":"write","prompt":"Describe the same cluttered kitchen twice — once through a hungry child's eyes, once through a building inspector's. Let the DETAILS differ, not just the mood. 2-3 sentences each.","rubric":"Change WHICH details each observer notices (not just tone), showing POV as perception filtered through a specific mind."}},{"track":"Theory","source":"Barthes, Mythologies","title":"Everyday things carry hidden ideology","body":"Before 'Death of the Author,' Barthes wrote Mythologies — short, dazzling essays reading everyday things (wrestling, soap ads, a plate of steak, a new car) as 'myths' loaded with hidden meaning.\n\nHis key idea: culture makes historical, constructed things look 'natural' and obvious. A myth takes something political or contingent and dresses it up as common sense. For a writer this is an observation superpower: any ordinary object — a phone, a lawn, a wedding dress — is dense with assumptions about how life should be. The sofa isn't just a sofa; it's a claim about comfort, class, and what a home should be.","keytakeaway":"Everyday objects carry hidden ideology — culture makes the constructed look 'natural.' Ordinary things are dense with meaning.","practice":{"type":"reflect","prompt":"Which appeals to you most as a writer's project?","options":["Exposing the hidden meaning in ordinary things","Telling a gripping story that moves fast","Rendering inner emotional truth","Playing with language and form itself"],"profileKey":"writerly_project"}}]},{"day":8,"theme":"Ranking ideas: subordination","lessons":[{"track":"Sentence","source":"Sentence craft — subordination","title":"Demoting the lesser idea — the cure for the buried point","body":"This is the single most important pattern for your second pain point: 'the parts pile up and the point gets buried.'\n\nCoordination (yesterday) makes ideas EQUAL. Subordination makes one idea the MAIN point and the other a supporting detail. You do it with subordinating conjunctions — because, although, when, while, since, if, as, after, though — which demote a clause to a lesser rank.\n\nCompare:\n• 'The rain stopped and we went outside.' (coordination — two equal events)\n• 'When the rain stopped, we went outside.' (subordination — the rain is now just the SETUP; 'we went outside' is the main point)\n\nWHY this fixes buried points: when everything is an equal clause joined by 'and,' the reader can't tell what matters most — every part has the same rank, so the point drowns in the pile. Subordination RANKS the ideas for the reader. It says: this clause is the main event; that one is background. You're doing the reader's prioritizing for them, in the structure itself.\n\nThe mechanical key — which clause should be the main (independent) one? The one carrying your point. Whatever you subordinate becomes background; whatever you leave as the main clause becomes the emphasis. So subordination is also an emphasis tool: 'Although she won, she felt empty' emphasizes the emptiness; 'Although she felt empty, she won' emphasizes the winning. Same facts, opposite point — decided entirely by which idea you demote.\n\nThis is the deep fix for pile-up: a heap of equal clauses becomes clear the moment you decide which ONE is the point and subordinate the rest to it.","keytakeaway":"Subordination (because, although, when, while, since, if) demotes a clause to background and leaves the main point in the independent clause. It RANKS ideas so the point can't drown. Whichever clause you keep independent gets the emphasis.","practice":{"type":"combine","prompt":"Each item is a pile of equal clauses where the point drowns. Rewrite each using subordination so the MAIN point (given in brackets) is the independent clause and the rest is demoted to background. Do all three.\n\n1. The meeting ran long and everyone was tired and no decision was reached. [point: no decision was reached]\n2. She had trained for months and the weather was terrible and she still won the race. [point: she won]\n3. He apologized and he sent flowers and she didn't forgive him. [point: she didn't forgive him]","rubric":"Each answer should leave the bracketed point as the main independent clause and demote the other clauses with subordinators (although, even though, despite the fact that, after). e.g. 'Although the meeting ran long and everyone was tired, no decision was reached.'"}},{"track":"Craft","source":"Shklovsky, On the Theory of Prose","title":"Fabula and syuzhet (story vs. arrangement)","body":"The Russian Formalists split narrative into two layers. The FABULA is the raw chronological events — what happened, in order. The SYUZHET is how those events are arranged and revealed in the actual text — the ordering, the withholding, the flashbacks, the delays.\n\nA murder mystery has a simple fabula (someone killed someone) but an elaborate syuzhet (we learn it last, out of order, through clues). WHY this is one of the most practical ideas in narrative theory: it means the ART is in the arrangement, not just the events. You can take dull chronological material and make it gripping purely through how you sequence and reveal it. Story is what happened; plot is how you tell it.","keytakeaway":"Fabula = events in order. Syuzhet = how you arrange/reveal them. The art is in the arrangement — you can make dull events gripping by re-sequencing.","practice":{"type":"write","prompt":"Take a dull fabula — 'a woman loses her keys, searches all day, finds them in her coat' — and describe how you'd arrange the SYUZHET to make it gripping. Where would you start? What would you withhold?","rubric":"Manipulate order and revelation (start at the discovery, withhold what she's really searching for) rather than just retelling events in sequence."}},{"track":"Theory","source":"Said, Orientalism","title":"How writing constructs the 'other'","body":"Said showed that centuries of Western writing about 'the East' didn't neutrally describe it — it CONSTRUCTED an 'Orient' that was exotic, backward, irrational, and feminine, largely to define the West as its opposite (rational, advanced, masculine).\n\nThe point isn't only about East and West; it's a general lesson about representation. When you write about any group you're not part of, you risk producing a projection — a version that says more about your own culture's needs and fears than about the people themselves. This is a discipline of self-awareness: whose gaze is this? Am I describing people, or using them as a mirror or backdrop for someone else's story?","keytakeaway":"Writing about 'others' can construct a projection that serves the writer's own culture. Ask: whose gaze is this?","practice":{"type":"reflect","prompt":"When you write characters very different from yourself, what's your instinct?","options":["Research deeply and try to render them truly","Write mainly what I know from the inside","Avoid it — I worry about getting it wrong","I hadn't examined my instinct here"],"profileKey":"otherness"}}]},{"day":9,"theme":"When the join fails: splices and run-ons","lessons":[{"track":"Sentence","source":"Sentence craft — comma splices & run-ons","title":"Why gluing two sentences with a comma fails, mechanically","body":"Now that you know coordination and subordination, the comma splice stops being a mystery rule and becomes obvious.\n\nA comma splice: 'The rain stopped, we went outside.' Two complete independent clauses joined by only a comma.\n\nWHY it fails — the real mechanism: a comma is a weak, low-ranking mark. Its job is to separate PARTS within a sentence (items in a list, a modifier from the core). It does not have the strength to mark the boundary BETWEEN two complete sentences. When you ask it to hold two independent clauses together, you're using a hinge to do a wall's job. The reader hits the comma, expects a mere part to follow, and instead runs into a whole new sentence — a small collision. (A run-on is the same crime with no comma at all: 'The rain stopped we went outside.')\n\nSo the fix is just: use a mark or a word STRONG enough for the job. And each choice does something different — this is where mechanics becomes style:\n• PERIOD: 'The rain stopped. We went outside.' — full stop, two separate thoughts, maximum separation.\n• SEMICOLON: 'The rain stopped; we went outside.' — WHY a semicolon works where a comma doesn't: it's specifically built to join two independent clauses that are closely related, marking them as equal and linked. Use it when the two thoughts belong together.\n• COORDINATION: 'The rain stopped, and we went outside.' — comma PLUS conjunction is strong enough; the conjunction supplies the strength the comma lacks.\n• SUBORDINATION: 'When the rain stopped, we went outside.' — demotes one clause so there's only one independent clause left, and the problem dissolves.\n\nFour fixes, four different rhythms and emphases. The error is always the same (a weak mark doing a strong job); the fix you choose is a style decision.","keytakeaway":"A comma splice fails because a comma is too weak to mark the boundary between two complete sentences — it separates PARTS, not whole clauses. Fix with a period, semicolon (built to join related independent clauses), coordination (comma + conjunction), or subordination. The fix you pick is a style choice.","practice":{"type":"combine","prompt":"Each is a comma splice or run-on. Fix each TWICE, using two DIFFERENT methods, and note which methods you used and why that choice fits. Do all three.\n\n1. The experiment failed, the team started over.\n2. She loved the city she couldn't afford to stay.\n3. He knocked twice, no one answered.","rubric":"Each fix should remove the splice with a period, semicolon, comma+conjunction, or subordination — and the two versions per item should use DIFFERENT methods. Bonus for noting why a given method suits the relationship between the clauses (e.g. subordination when one clause is clearly background)."}},{"track":"Craft","source":"E.M. Forster, Aspects of the Novel","title":"Rhythm in fiction","body":"Forster ends his lectures on something subtle: rhythm. Not sentence rhythm, but the larger musical patterning of a novel — an image, phrase, or motif that recurs, changing meaning each time it returns.\n\nHe cites a little musical phrase in Proust that surfaces again and again, gathering weight. WHY repetition-with-variation creates unity: each recurrence 'rhymes' with the earlier ones, so the reader feels a pattern connecting distant parts of the book — but because it's varied, it deepens rather than bores. When you plan something longer than a scene, think about what will RETURN, and how it will have changed when it does.","keytakeaway":"Rhythm in fiction = a motif that recurs with variation, gathering meaning each time. Recurrence unifies; variation keeps it from boring.","practice":{"type":"write","prompt":"Name a single image or object you'd want to RECUR three times across a story, and describe how its meaning shifts each time (e.g. a coat: warmth → burden → memory).","rubric":"Pick one concrete motif and show how recurrence with variation would deepen or change its meaning across the story."}},{"track":"Theory","source":"Gilbert & Gubar, The Madwoman in the Attic","title":"The 'madwoman' and buried rage","body":"Gilbert and Gubar's landmark work argued that 19th-century women writers, forbidden to express anger or ambition directly, often split their heroines: the docile, proper 'angel' figure, and a wild, raging 'madwoman' double (like Bertha Mason locked in Rochester's attic in Jane Eyre) who embodies everything the author couldn't say openly.\n\nThe madwoman is the return of the repressed. Beyond its feminist argument, this gives you a device: a character's disowned traits can be externalized into a double, a shadow, a figure who acts out what the protagonist won't admit. The locked-away self always finds a way into the story.","keytakeaway":"Disowned traits can be externalized as a 'double' — the raging shadow that acts out what a character represses.","practice":{"type":"reflect","prompt":"Closest to how you'd handle a character's darkest impulses?","options":["Let them speak directly, on the surface","Split them off into a shadow/double figure","Bury them in subtext and let readers sense them","Not sure — I want to try each"],"profileKey":"darkness_handling"}}]},{"day":10,"theme":"Packing in detail: the appositive","lessons":[{"track":"Sentence","source":"Sentence craft — the appositive","title":"Renaming a noun to add detail without a new sentence","body":"An appositive is a noun phrase that renames the noun right beside it: 'My brother, a stubborn optimist, refused to sell.' 'A stubborn optimist' renames 'my brother.' It sits next to the noun, set off by commas, adding information without needing a verb or a new sentence.\n\nWHY it's such an efficient tool: it lets you fold a whole second statement INTO the sentence you're already writing, with no repetition and no extra clause. Compare the choppy version: 'My brother is a stubborn optimist. He refused to sell.' The appositive collapses those into one, dropping the redundant 'my brother is / he.' You get the information for free, riding alongside the main clause instead of stopping the sentence to add it.\n\nThis directly serves 'I can't combine my sentences.' Whenever you have two sentences and one just RENAMES or DESCRIBES the subject of the other, the describing one can usually become an appositive:\n• 'Marie ran the lab. She was a chemist by training.' → 'Marie, a chemist by training, ran the lab.'\n• 'The house sat empty. It was a crumbling Victorian.' → 'The house, a crumbling Victorian, sat empty.'\n\nPlacement (connects to Day 6 branching):\n• Mid: 'Marie, a chemist by training, ran the lab.' (interrupts — keep it short)\n• Right: 'She ran the lab, a chemist by training.' — risky, can attach to the wrong noun; usually rename right after the noun.\n• Left: 'A chemist by training, Marie ran the lab.' (front-loaded emphasis on the description)\n\nWHY the commas matter: they signal the appositive is EXTRA, removable information (nonrestrictive) — the sentence still stands if you lift it out. That removability is the test for whether you've built a true appositive.","keytakeaway":"An appositive renames a noun beside it ('my brother, a stubborn optimist'), folding a second statement in with no extra clause or repetition. Use it to combine two sentences when one just describes the other's subject. Commas mark it as removable.","practice":{"type":"combine","prompt":"Combine each pair into ONE sentence by turning the describing sentence into an appositive. Do all three, and try varying placement (front, middle) across them.\n\n1. Dr. Reyes delivered the verdict. She was a woman who never softened bad news.\n2. The café closed last spring. It was our only meeting place.\n3. Toby led the search. He was a retired tracker with forty years in the hills.","rubric":"Each answer should fold the describing sentence into an appositive (a noun phrase renaming the subject), set off by commas, with no repeated subject. e.g. 'Dr. Reyes, a woman who never softened bad news, delivered the verdict.'"}},{"track":"Craft","source":"Craft review","title":"Your craft toolkit so far","body":"You now hold a real toolkit: flat vs. round characters (Forster), free indirect style and the telling detail and perspectival POV (Wood), story vs. plot (Forster), desire as motor (Brooks), defamiliarization and fabula/syuzhet (Shklovsky), rhythm/recurrence (Forster).\n\nThese fall into two families: tools for the MOMENT (free indirect style, telling detail, defamiliarization) and tools for STRUCTURE (plot vs. story, desire, arrangement, rhythm). Most writers lean toward one family by instinct. Notice which pulled you in more over these ten days — it's an early reading of the writer you're becoming.","keytakeaway":"Craft tools split into MOMENT (texture) and STRUCTURE. Most writers lean one way — noticing which is an early read on your style.","practice":{"type":"reflect","prompt":"Looking back at your exercises, which came more naturally?","options":["The close-in texture (sentences, details, voice)","The structural (plot, desire, arrangement)","Genuinely both","Neither felt natural yet — both are work"],"profileKey":"texture_vs_structure"}},{"track":"Theory","source":"Theory review","title":"Ten days of lenses","body":"You've handled the major beginner lenses: Auerbach (surface vs. depth; high/low mixing), Barthes (the reader makes meaning; hidden ideology), Foucault (the author-function), Woolf (material conditions), Eagleton (literature and its social world), Said (the 'other'), Gilbert & Gubar (repression and the double).\n\nEach is a QUESTION you can ask of any text, including your own: What's withheld? Who completes the meaning? What does this assume about money and power? Whose gaze? What's repressed? A theory isn't a verdict; it's a question that opens a text up. The best writers read their own drafts through several at once.","keytakeaway":"Each theory is a QUESTION to ask of a text, not a verdict. Read your own drafts through several lenses.","practice":{"type":"reflect","prompt":"Which theoretical QUESTION do you most want to bring into your own writing?","options":["What am I withholding vs. explaining? (Auerbach)","What does my work assume about money/power? (Eagleton)","Whose gaze am I writing from? (Said)","What's being repressed, and where does it surface? (Gilbert & Gubar)"],"profileKey":"favorite_lens"}}]},{"day":11,"theme":"Matched structures: parallelism","lessons":[{"track":"Sentence","source":"Sentence craft — parallelism","title":"Why matched grammatical forms read cleanly","body":"Parallelism means giving ideas of equal weight the same grammatical FORM. 'She likes swimming, hiking, and biking' — three -ing nouns, matched. Break the pattern and it jars: 'She likes swimming, to hike, and biking.'\n\nWHY the mismatch hurts, mechanically: when a reader meets a series, the first item sets up a pattern, and the mind PREDICTS the rest will follow it. Each matched item confirms the prediction and reads frictionlessly. A mismatched item breaks the prediction — the reader stumbles, has to re-parse, and momentarily loses the thread. Parallel form isn't a decorative nicety; it's keeping a promise your first item made to the reader's ear.\n\nThis is also why parallelism makes comparisons and lists so much clearer: matched forms let the reader line the items up and see the relationship instantly, instead of untangling three different shapes. 'The report was clear, thorough, and persuasive' (three adjectives — instantly a set) beats 'The report was clear, thorough, and it persuaded people' (two adjectives then a clause — the reader has to regroup).\n\nWhere it matters most — CORRELATIVE pairs: not only...but also, either...or, both...and, neither...nor. WHY these especially: the pair explicitly promises symmetry, so whatever follows the first half must match what follows the second. 'She was not only brilliant but also kind' (adjective / adjective — matched). 'She not only was brilliant but also kind' breaks it (verb phrase / adjective). Put the same part of speech after each half of the pair.\n\nThe practical habit: whenever you write a series or a comparison, check that every item wears the same grammatical clothes. If one is dressed differently, either re-dress it to match or pull it out of the series.","keytakeaway":"Parallelism = equal ideas in matching grammatical form. It reads cleanly because the first item sets a pattern the reader predicts; a mismatch breaks the prediction and forces a re-parse. Correlatives (not only...but also) demand especially strict symmetry.","practice":{"type":"combine","prompt":"Each sentence has faulty parallelism. Rewrite each so the items match in grammatical form, and note what you matched. Do all three.\n\n1. The course teaches you to write clearly, thinking critically, and how to argue well.\n2. He was admired for his honesty, his intelligence, and because he worked hard.\n3. She not only finished the marathon but also she raised ten thousand dollars.","rubric":"Each answer should put every series item (or each half of a correlative) in the same grammatical form. e.g. 'The course teaches you to write clearly, think critically, and argue well' (three bare infinitives)."}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"Dialogue that isn't just information","body":"Weak dialogue exists only to transmit plot information ('As you know, Bob, we've been married ten years'). Strong dialogue does several things at once: it characterizes through HOW people speak, creates subtext (what's meant under what's said), and advances tension.\n\nWHY real speech works on the page: people rarely say what they mean directly — they evade, deflect, answer a different question than the one asked. The gap between what's said and what's meant is where the reader does active work, and that work is the pleasure. The most revealing line is often the one that dodges. When you write dialogue, ask: what is each person NOT saying? What are they after?","keytakeaway":"Good dialogue characterizes and creates subtext — people dodge and talk past each other. The gap between said and meant is where the reader works.","practice":{"type":"write","prompt":"Write a 4-6 line exchange between two people where the real subject (one wants to break up) is NEVER stated directly. Let subtext carry it.","rubric":"Convey the buried tension entirely through indirection — what's avoided, deflected, or said sideways — without stating the real subject."}},{"track":"Theory","source":"Auerbach, Mimesis","title":"The realism revolution","body":"Auerbach traces how Western literature slowly learned to take ordinary reality seriously — to represent everyday life, in all its texture, as worthy of serious art. Early on, only the elevated got serious treatment; the common was for comedy. Over centuries that inverted, culminating in the 19th-century realist novel, where a provincial marriage or a clerk's day carries full tragic seriousness.\n\nRealism in this deep sense isn't 'describing accurately' — it's granting serious moral and emotional weight to ordinary, historically-situated life. Ask of your own work: am I treating ordinary experience as fully serious, fully real?","keytakeaway":"Deep realism = granting full serious weight to ordinary, historically-situated life, not just 'accurate description.'","practice":{"type":"reflect","prompt":"Where does your writing instinct sit on realism?","options":["Ground everything in specific, ordinary reality","Heighten and stylize away from the literal","Blend realism with the fantastic/strange","Still discovering my relationship to realism"],"profileKey":"realism_stance"}}]},{"day":12,"theme":"What attaches to what: modifiers","lessons":[{"track":"Sentence","source":"Sentence craft — modifiers & attachment","title":"Why a misplaced modifier reads wrong — and the dangler","body":"A modifier attaches to the nearest thing it can plausibly grab. That single fact explains every misplaced-modifier error.\n\n'Walking through the door, the clock struck three.' Read literally, the clock is walking — because 'walking through the door' is an opening modifier looking for a subject, and the nearest noun it finds is 'the clock.' It grabs whatever's closest, and here that's absurd. This is a DANGLING modifier: the thing it's supposed to describe isn't actually in the sentence.\n\nWHY it happens: an opening -ing or -ed phrase has no subject of its own, so it borrows the subject of the main clause that follows. Your MIND knows you meant 'I heard the clock' — but the SENTENCE only offers 'the clock' as the subject, so grammatically the clock does the walking. The reader parses by proximity and rank, not by your intention. Fix: make the borrowed subject the right one. 'Walking through the door, I heard the clock strike three.' Now the phrase grabs 'I' — correct.\n\nThe same proximity principle governs the small but meaning-changing placement of words like 'only':\n• 'She only ate the soup.' = she did nothing but eat it (didn't admire it, didn't pay for it).\n• 'She ate only the soup.' = she ate nothing but the soup.\nWHY: 'only' modifies whatever it sits next to. Put it beside the word you mean to limit. Misplace it and you've said something you didn't mean — grammatically correct, factually wrong.\n\nThe habit: after any opening phrase, check that the very next noun is the thing the phrase describes. And put limiting words (only, just, even, almost) directly beside what they limit. Modifiers don't read your mind; they grab their neighbor.","keytakeaway":"A modifier grabs its nearest plausible neighbor, not your intention. A dangling modifier's real target isn't in the sentence, so it grabs the wrong subject — give the main clause the right subject. Place limiting words (only, just) directly beside what they limit.","practice":{"type":"diagnose","prompt":"Each sentence has a modifier problem OR is correct. Identify what's wrong (or that it's fine).","items":[{"sentence":"Having finished the assignment, the TV was turned on.","options":["dangling modifier — 'the TV' didn't finish the assignment","correct as written","misplaced 'only'"],"answer":0,"explain":"'Having finished' borrows the main clause's subject, but that's 'the TV' — so the TV finished the assignment. Fix: 'Having finished the assignment, she turned on the TV.'"},{"sentence":"Covered in mud, the hikers reached the summit.","options":["dangling modifier","correct as written","comma splice"],"answer":1,"explain":"'Covered in mud' correctly grabs 'the hikers' — the nearest noun IS the intended one. Fine as written."},{"sentence":"He almost drove his kids to school every day.","options":["correct","misplaced 'almost' — sounds like he nearly drove them (but didn't)","dangling modifier"],"answer":1,"explain":"'Almost' sits beside 'drove,' so it limits the driving — he nearly-but-didn't drive them. Meaning intended: 'He drove his kids to school almost every day.'"},{"sentence":"Running late, Maria grabbed her coat and left.","options":["dangling modifier","correct as written","faulty parallelism"],"answer":1,"explain":"'Running late' grabs 'Maria' — the correct, intended subject. Fine."},{"sentence":"To improve the report, several changes were suggested.","options":["dangling modifier — who is improving?","correct","comma splice"],"answer":0,"explain":"'To improve the report' needs a person doing the improving, but the subject is 'several changes.' Fix: 'To improve the report, the editor suggested several changes.'"}]}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"Metaphor and the fresh comparison","body":"Wood prizes metaphor that makes us see — a comparison so apt and unexpected it reorganizes perception — versus the dead metaphor we no longer notice ('a wave of nausea,' 'the heart of the matter').\n\nWHY the best metaphors work: they yoke two things whose likeness we hadn't noticed, and the surprise is in the RIGHTNESS — recognition and surprise at once. A dead metaphor has lost its surprise; a strained one ('the moon hung like a...') has the surprise but not the rightness. The test: does it make the thing clearer AND stranger, or just decorate? A great metaphor is a tiny act of defamiliarization.","keytakeaway":"Good metaphor clarifies AND surprises by yoking an unnoticed likeness — rightness plus surprise. Avoid dead metaphors and show-off similes.","practice":{"type":"write","prompt":"Write ONE fresh metaphor or simile for a common experience — waiting anxiously, or checking your phone compulsively. Avoid any comparison you've heard before.","rubric":"Offer an apt, surprising, precise comparison that illuminates the experience — not a cliché and not a strained show-off image."}},{"track":"Theory","source":"Foucault, What Is an Author? (discourse)","title":"Discourse, power, and what can be said","body":"Behind Foucault's author essay sits his larger project: what counts as knowledge, truth, or sayable is shaped by 'discourse' — systems of statements backed by institutions and power. In any era, some things can be said and taken seriously; others are unthinkable or unspeakable.\n\nPower isn't just top-down repression; it's productive — it produces the categories we think in. For a writer, this reveals the invisible frame around your own work: what does your time treat as obvious, natural, unsayable? The most interesting writing often works at the edges of the sayable.","keytakeaway":"'Discourse' shapes what can be said and thought in an era. The edge of the sayable is fertile ground for writing.","practice":{"type":"reflect","prompt":"Are you drawn to writing at the 'edge of the sayable' — naming what your moment avoids?","options":["Yes — that tension is exactly what I want to write","Sometimes — I circle it carefully","No — I'd rather write beauty or story than provocation","Interesting, but I hadn't thought this way"],"profileKey":"sayable_edge"}}]},{"day":13,"theme":"The music of length","lessons":[{"track":"Sentence","source":"Sentence craft — rhythm & sentence length","title":"Why varying sentence length keeps the reader awake","body":"You can now build long sentences (cumulative, periodic) and clear short ones (a tight core). The art is in ALTERNATING them.\n\nWHY monotony deadens, mechanically: a string of same-length sentences produces a metronomic rhythm, and the human ear tunes out steady repetition — the same way you stop hearing a clock tick. A run of medium sentences, however clear each one is, becomes a drone the reader stops attending to. Variety keeps the rhythm unpredictable, and unpredictability keeps attention.\n\nAnd length is EXPRESSIVE, not just decorative:\n• A long, flowing sentence enacts continuity, accumulation, being caught up in something — the syntax mimics the experience of duration.\n• A short sentence stops the reader. It lands. WHY a short sentence hits hard after long ones: the contrast itself creates emphasis — after the ear has settled into a long rhythm, an abrupt short sentence is a jolt. This is the most reliable emphasis trick in prose: follow a long, winding sentence with a short blunt one, and the short one detonates. (Notice this paragraph just did it.)\n\nThe practical technique — read your paragraph aloud and listen for the pattern of lengths. If every sentence is roughly the same size, you have a drone. Break it: combine two into a longer flowing one (cumulative), and cut another to a punchy fragment of its former self. You're composing a rhythm, not just stacking correct sentences.\n\nThis is the payoff of everything so far: correctness gets you clear sentences; VARYING their length and shape gets you prose that a reader can't stop reading.","keytakeaway":"Vary sentence length: same-length sentences drone and the ear tunes out. Length is expressive — long sentences enact duration, short ones land hard, and a short sentence after long ones detonates by contrast. Read aloud to hear the pattern.","practice":{"type":"combine","prompt":"This passage is all medium-length sentences — a drone. Rewrite it, varying the lengths: combine some into a flowing longer sentence and cut at least one to a short, punchy sentence for emphasis.\n\n'The house was empty when I arrived. I walked from room to room slowly. Everything was covered in white sheets. The furniture looked like sleeping ghosts. I stopped in the doorway of my old bedroom. I did not go inside.'","rubric":"A strong answer varies sentence length noticeably — merging several into a longer flowing sentence and leaving at least one very short sentence for impact — rather than keeping the uniform medium rhythm."}},{"track":"Craft","source":"Shklovsky, On the Theory of Prose","title":"Delay and the staircase of retardation","body":"Shklovsky observed that stories deliberately SLOW the reader down — through digressions, repetitions, obstacles, 'stepped' construction — because the pleasure is in the delay of resolution, not just the resolution itself.\n\nHe called these retarding devices: the three brothers who each try in turn (the third succeeds), the riddle posed three times. WHY the 'inefficiency' is the point: a folktale could state the outcome in one line, but then there'd be no experience, no suspense, nothing to feel — the delay is what converts information into experience. When you're tempted to rush to the payoff, remember the reader came for the climb.","keytakeaway":"Stories deliberately DELAY through repetition and digression — the 'inefficiency' (the staircase) converts information into experience.","practice":{"type":"write","prompt":"Take a one-line outcome ('the knight opens the box and finds it empty'). Build a 'staircase' that delays the reveal — at least three steps that prolong it meaningfully. Describe the steps.","rubric":"Construct genuine retarding devices (repetition, escalating attempts, digression) that prolong the reveal meaningfully rather than just stalling."}},{"track":"Theory","source":"Woolf, A Room of One's Own","title":"The androgynous mind","body":"Late in A Room of One's Own, Woolf offers a striking idea: the great creative mind is 'androgynous' — it fuses masculine and feminine and writes without a grievance or a thumb on the scale.\n\nShe worried that writing consumed by anger or the need to prove a point becomes distorted, unable to see wholly. The truly creative writer achieves a kind of incandescence — a mind so fully fired that all obstruction is consumed. This is a subtle warning: even righteous anger, poured raw into art, can warp it. Emotion fuels the work; it shouldn't rule it.","keytakeaway":"Woolf's 'androgynous mind' = creative incandescence free of grievance. Emotion fuels art; it shouldn't warp it.","practice":{"type":"reflect","prompt":"When you write about something you feel strongly about, what happens?","options":["The intensity makes the writing better","I struggle to see other sides — it narrows me","I deliberately cool it down before writing","I haven't written from strong conviction yet"],"profileKey":"conviction_and_craft"}}]},{"day":14,"theme":"Controlling emphasis by position","lessons":[{"track":"Sentence","source":"Sentence craft — emphasis & word order","title":"Why the END of a sentence is the strongest position","body":"This is the master key to your third pain point — controlling emphasis — and it has a real mechanism behind it.\n\nThe principle: the END of a sentence carries the most emphasis; the beginning carries the second most; the middle is weakest. So whatever you put last is what the reader remembers.\n\nWHY the end is strongest: a sentence isn't complete in the reader's mind until it ends, so the final words are what the mind is holding at the moment of closure — they get the 'last word,' literally. They also sit right before the pause (period), and that silence lets them ring. Anything you bury in the middle gets passed over on the way to the end. This is 'end-weight,' or 'end-focus.'\n\nSo when your important idea 'ends up in the wrong place,' the fix is mechanical: MOVE IT TO THE END.\n• Weak: 'Humanity has hardly advanced in fortitude, though it has advanced in many other ways.' (the key point — no advance in fortitude — is buried mid-sentence)\n• Strong: 'Humanity has advanced in many ways, but it has hardly advanced in fortitude.' (the point now lands last)\n\nTwo related tools:\n• FRONTING — moving something to the front for the SECOND-strongest slot and to set a frame: 'That mistake, I will never forget.' The unusual order flags emphasis because it breaks the expected subject-first pattern — the reader notices the disruption.\n• END-WEIGHT for balance — put short elements first and the long, heavy element last: 'What she wanted was a single uninterrupted hour to think.' Ending on the heavy phrase feels balanced; front-loading it ('A single uninterrupted hour to think was what she wanted') feels top-heavy, because the reader has to hold the long phrase open before learning what it's doing.\n\nThe habit: for any sentence carrying a point, ask 'what's the one thing I want remembered?' — then get it to the final position. You are no longer at the mercy of where the idea fell.","keytakeaway":"The end of a sentence is the strongest position — it's what the reader holds at closure, ringing before the pause. Move your key idea to the end. Fronting grabs the second-strongest slot by breaking expected order; end-weight puts the long/heavy element last for balance.","practice":{"type":"combine","prompt":"Rewrite each so the most important idea (in brackets) lands in the emphatic FINAL position. Do all three.\n\n1. The bridge, which had stood for a century, collapsed in four seconds. [point: it collapsed in seconds]\n2. She got the promotion she'd wanted for years, but it meant nothing to her now. [point: it meant nothing to her]\n3. We lost the house, the savings, and eventually the marriage, over one bad decision. [point: over one bad decision]","rubric":"Each answer should place the bracketed idea at the very end of the sentence, moving less important material earlier. e.g. 'The bridge had stood for a century; it collapsed in four seconds.'"}},{"track":"Craft","source":"E.M. Forster, Aspects of the Novel","title":"The life of a character (Homo fictus)","body":"Forster distinguishes the people of a novel (Homo fictus) from real people. Real people are largely unknowable — we never fully see inside anyone. But in fiction, the writer can grant TOTAL access to a character's inner life, or withhold it entirely; this control over interiority is fiction's unique power.\n\nWHY calibration matters: a character all surface feels thin (we sense there's nothing inside), but a character fully explained feels airless (real people keep their mystery, so total access reads as unreal). The art is in the ratio — how much inner life to reveal, how much to keep opaque.","keytakeaway":"Fiction can grant total or zero access to a character's inner life. Too opaque is thin; too explained is airless. Calibrate the ratio.","practice":{"type":"write","prompt":"Write a short paragraph about a character at a funeral where you reveal ONE private thought that contradicts their outward behavior — and leave the rest opaque.","rubric":"Grant selective interior access — one revealing private thought against the public surface — rather than explaining everything or nothing."}},{"track":"Theory","source":"Eagleton, Marxism and Literary Criticism","title":"Form itself carries ideology","body":"Eagleton's deeper point: it's not just the CONTENT of a book that's ideological — the FORM is too. The realist novel's tidy resolved endings; the reassuring omniscient narrator who explains everything; the individual hero whose choices drive events — these formal features quietly embody a worldview (that the world is orderly, knowable, driven by individuals rather than systems).\n\nA fragmented, unresolved, collective form makes a different claim about reality. So your formal choices — how you end, who narrates, whether you resolve — aren't neutral craft decisions; they smuggle in assumptions about how the world works.","keytakeaway":"Form carries ideology too — neat resolution, omniscient narration, and the individual hero all embody a worldview. Form is a claim about reality.","practice":{"type":"reflect","prompt":"How do you feel about tidy, resolved endings?","options":["I love resolution — give me a satisfying close","I prefer ambiguity and open endings","It depends entirely on the story","I hadn't thought of endings as making a 'claim'"],"profileKey":"resolution_preference"}}]},{"day":15,"theme":"Review: diagnose your own sentences","lessons":[{"track":"Sentence","source":"Sentence craft — review & diagnosis","title":"Putting the patterns together — the editor's eye","body":"Halfway. You now have the whole construction kit: find the true subject, build on one core, extend right (cumulative) or delay for suspense (periodic), attach modifiers by branch, join equals (coordination) or rank ideas (subordination), fix weak joins (splices), pack detail (appositives), match forms (parallelism), place modifiers so they don't dangle, vary length for rhythm, and drive emphasis to the end.\n\nThe skill now is DIAGNOSIS — reading your own sentence and seeing what's wrong and why. This is different from writing correctly the first time; even strong writers fix on the second pass. The editor's questions, in order:\n1. What's my core? (one subject + verb) Is it clear, or has the sentence grown a competing core?\n2. Is my point in the emphatic END position, or buried?\n3. Are equal ideas coordinated and unequal ideas subordinated — or is everything strung with 'and'?\n4. Does every modifier grab the right neighbor?\n5. Do series and pairs match in form?\n6. Is the rhythm varied, or a drone?\n\nWHY reading ALOUD is the master diagnostic: your ear catches what your eye skims. A comma splice sounds like a stumble; a dangling modifier sounds faintly absurd; a monotonous rhythm sounds like a drone; a buried point sounds anticlimactic. You spent years absorbing the sound of English before you could name a single rule — that ear is your most trained instrument. Reading aloud puts the trained ear back in charge of the under-trained eye.","keytakeaway":"Editing = diagnosis, a separate skill from first-draft writing. Run the checklist: core, end-emphasis, coordinate vs. subordinate, modifier attachment, parallel form, rhythm. Read aloud — your ear catches what your eye skims.","practice":{"type":"combine","prompt":"This sentence breaks several things at once. Diagnose it (list what's wrong), then rewrite it well. \n\n'Walking into the crowded room the noise was overwhelming, there were people everywhere and everyone was talking and the music was loud and I only wanted to find my sister.'\n\nThen do the same for one sentence of YOUR OWN — write a messy sentence on any topic, diagnose it, and fix it.","rubric":"Should catch: dangling modifier ('walking' grabs 'the noise'), comma splice, monotonous 'and...and' coordination that should be subordinated/varied, and buried point ('I only wanted to find my sister' — the emotional core — should land at the end). The self-authored example should show genuine diagnosis, not just a rewrite."}},{"track":"Craft","source":"Craft midpoint — integration","title":"Combining tools in one passage","body":"You've collected craft tools one at a time. Real writing uses several at once. A strong paragraph might enter free indirect style (Wood), notice perspectival details (Wood), plant a telling specific (Wood), defamiliarize one ordinary thing (Shklovsky), and carry the pressure of a desire (Brooks).\n\nThe tools don't compete — they layer. WHY combining is also diagnostic: the tools you REACH for when combining freely reveal your instincts. Don't force all of them; pick two or three that suit you and make them work together.","keytakeaway":"Real passages layer several craft tools at once. The ones you reach for by instinct reveal your emerging style.","practice":{"type":"write","prompt":"Write one short paragraph (5-7 sentences) that deliberately combines at least THREE craft tools you've learned. Afterward, name which three you used.","rubric":"Integrate three named techniques into a coherent passage rather than demonstrating them in isolation, and correctly identify them."}},{"track":"Theory","source":"Theory midpoint — your reading self","title":"The lenses as a set of questions","body":"The theories you've met aren't a hierarchy where the newest is 'most true.' They're complementary questions, and a mature reader keeps several live at once. Faced with any text — a novel, an ad, your own draft — you can ask: What's on the surface vs. withheld (Auerbach)? Where is meaning made — author or reader (Barthes/Foucault)? What material conditions shaped this (Woolf/Eagleton)? Whose gaze (Said)? What's repressed (Gilbert & Gubar)?\n\nNotice which question comes to mind FIRST and most naturally. That reflex is part of your critical fingerprint — and it tends to shape what you write, not just how you read.","keytakeaway":"The theories are complementary questions to keep live at once. The one you reach for first is part of your critical fingerprint.","practice":{"type":"reflect","prompt":"Faced with any story, which question rises FIRST in your mind?","options":["What's being hidden or withheld here?","What does this assume about power and money?","Whose perspective is missing?","What's this text repressing?"],"profileKey":"first_question"}}]},{"day":16,"theme":"The engine of the sentence: verbs","lessons":[{"track":"Sentence","source":"Sentence craft — active vs. passive voice","title":"Why active voice usually lands harder — and when passive is right","body":"In the ACTIVE voice, the subject does the verb: 'The committee approved the plan.' In the PASSIVE, the subject receives the verb: 'The plan was approved by the committee.'\n\nWHY active usually hits harder: active voice follows the mind's natural story order — actor, action, thing-acted-on. The reader meets the doer first and watches them act, which is vivid and direct. Passive reverses this: it leads with the thing acted upon and often drops the actor entirely ('The plan was approved' — by whom?). It takes more words and adds a layer of grammatical machinery ('was...by') between the reader and the action. So passive tends to feel indirect, slower, and sometimes evasive.\n\nThat evasiveness is worth naming: 'Mistakes were made' is the classic passive dodge — it names an action with no actor, so no one is responsible. When you catch yourself in the passive, ask whether you're hiding the doer, on purpose or by accident.\n\nBUT — and this matters — passive is a TOOL, not an error. Use it deliberately when:\n• The actor is unknown or irrelevant: 'The bridge was built in 1890.' (who built it isn't the point)\n• The thing acted upon is the true topic: 'The painting was stolen last night.' (the painting is what we care about, not yet the thief)\n• You want to place the actor in the emphatic END position (connects to Day 14): 'The plan was approved by the one person we never expected.' — passive lets you save the actor for the punch.\n\nSo the rule isn't 'never use passive.' It's: default to active for directness, and reach for passive only when you have a REASON — topic, unknown actor, or end-emphasis.","keytakeaway":"Active voice (actor–action–object) follows the mind's natural order: direct and vivid. Passive leads with the receiver and can hide the actor ('mistakes were made'). Passive is a legitimate tool when the actor is unknown/irrelevant, the receiver is the real topic, or you want the actor at the emphatic end.","practice":{"type":"diagnose","prompt":"For each sentence: is it active or passive, and is the passive JUSTIFIED here?","items":[{"sentence":"The report was written by the intern in one night.","options":["passive, and weak here (active would be more direct)","active voice","passive, and justified"],"answer":0,"explain":"Passive. The actor (the intern) is known and interesting, so active is stronger: 'The intern wrote the report in one night.'"},{"sentence":"The vaccine was discovered in 1955.","options":["passive, but justified (actor unknown/irrelevant)","active voice","passive, and weak"],"answer":0,"explain":"Passive, but justified — the discovery/date is the point, not who did it. Active would force in an actor we don't need."},{"sentence":"A stray dog followed us all the way home.","options":["active voice","passive, weak","passive, justified"],"answer":0,"explain":"Active — the subject (dog) does the verb (followed). Direct and vivid."},{"sentence":"Serious concerns have been raised about the budget.","options":["passive — possibly dodging who raised them","active","passive, clearly justified"],"answer":0,"explain":"Passive with no actor — who raised the concerns? Often a dodge. If the source matters, name it: 'Auditors have raised serious concerns.'"}]}},{"track":"Craft","source":"James Wood, How Fiction Works","title":"Sympathy, distance, and the moral life of style","body":"Wood argues that HOW you narrate a character determines the reader's moral relationship to them. Free indirect style, by putting us inside a character's thoughts, tends to generate sympathy — even for the flawed, because understanding breeds intimacy. Ironic distance does the opposite: it holds a character up for judgment.\n\nWHY distance is a moral choice: closeness makes us inhabit a mind, and we forgive what we inhabit; distance makes us observe from outside, where we judge. Every choice of narrative distance quietly decides how the reader should FEEL about this person. Skilled writers modulate — pulling close for sympathy, drawing back for judgment.","keytakeaway":"Narrative distance is a moral choice: closeness breeds sympathy (we forgive what we inhabit), distance invites judgment. Modulate it deliberately.","practice":{"type":"write","prompt":"Write two short versions of the same moment — a man shoplifting — first CLOSE (free indirect, generating sympathy), then DISTANT (ironic, inviting judgment). 2-3 sentences each.","rubric":"Show how narrative distance changes the reader's moral relationship — the close version humanizes, the distant version judges — using the same events."}},{"track":"Theory","source":"Gilbert & Gubar + Woolf — synthesis","title":"Voice, permission, and the silenced self","body":"Woolf's Judith Shakespeare (talent with no room to grow) and Gilbert & Gubar's madwoman (rage with no permitted outlet) point at the same thing from two sides: writing is shaped not only by what you CAN say but by what you feel PERMITTED to say.\n\nEvery writer carries internalized limits — about what's 'appropriate' to write, what will be judged, what a person like you is 'allowed' to attempt. Some of the most powerful writing comes from noticing and crossing an internal boundary. Worth turning on your own practice: what are you not letting yourself write?","keytakeaway":"Writing is shaped by what you feel PERMITTED to say. The edge of your self-permission is often the edge of your best work.","practice":{"type":"reflect","prompt":"Is there something you sense you're NOT letting yourself write?","options":["Yes — subjects too personal or exposing","Yes — things I fear will be judged","Yes — forms/styles I think aren't 'for me'","Not that I've noticed — I write freely"],"profileKey":"self_permission"}}]},{"day":17,"theme":"Turning actions back into verbs","lessons":[{"track":"Sentence","source":"Sentence craft — nominalization","title":"Why 'make a decision' is weaker than 'decide'","body":"A nominalization is a verb (or adjective) turned into a noun: decide → decision, fail → failure, analyze → analysis, react → reaction, intend → intention. English lets you do this freely, and it's the single most common reason good clear thinking comes out as sludgy prose.\n\nWatch what happens: the real action gets frozen into a noun, and then the sentence needs a weak, empty verb to prop it up — make, have, conduct, perform, reach, provide. 'We made a decision' instead of 'we decided.' 'The committee conducted an analysis' instead of 'the committee analyzed.' 'There was a failure of the system' instead of 'the system failed.'\n\nWHY this weakens the sentence, mechanically: the VERB is where a sentence's energy lives — it's the action, the engine. When you nominalize, you take the action OUT of the verb slot (leaving a limp placeholder like 'made') and bury it inside a noun. Now nothing in the sentence is actually moving; the real event is embalmed as an object. You also add words (the empty verb plus usually an article: 'made A decision') and often push the real actor out of view. The prose feels abstract, static, and bureaucratic — because grammatically, it IS static: the engine slot is empty.\n\nThe fix, and it's almost mechanical: find the nominalization (often a noun ending in -tion, -ment, -ance, -al, -ure, -sis), and turn it back into the verb it came from. Let the real action reclaim the verb slot.\n• 'gave consideration to' → 'considered'\n• 'reached a resolution' → 'resolved'\n• 'the implementation of the policy was carried out' → 'we implemented the policy'\n\nThis is why Day 19's 'omit needless words' and today's lesson are cousins: nominalization is a major SOURCE of needless words. Fix the buried verb and the padding falls away on its own.","keytakeaway":"A nominalization freezes a verb into a noun (decide → decision), forcing a limp helper verb (make, have, conduct) into the engine slot and leaving the sentence static and wordy. Find the -tion/-ment/-ance noun and turn the action back into a real verb.","practice":{"type":"combine","prompt":"Each sentence buries its real action in a nominalization. Rewrite each so the action lives in a strong verb. Do all four.\n\n1. The team conducted an investigation of the failure.\n2. We need to make an improvement to the process.\n3. There was a significant reduction in costs after the merger.\n4. The manager gave consideration to the proposal and reached a decision.","rubric":"Each answer should convert the nominalization back to a verb and drop the empty helper verb. e.g. 'The team investigated the failure'; 'We need to improve the process'; 'Costs fell significantly after the merger'; 'The manager considered the proposal and decided.'"}},{"track":"Craft","source":"Peter Brooks, Reading for the Plot","title":"Beginnings, middles, and the shape of desire","body":"Brooks argues a narrative's shape mirrors the shape of desire. The beginning awakens a want; the middle is the space of complication and delay — desire deferred, detoured, prolonged (this is where the story LIVES); the end is where desire is discharged and the meaning of the whole becomes visible in retrospect.\n\nWHY the middle must resist resolution: if the want is satisfied too soon, the narrative dies — there's nothing left to pull the reader. Obstacles aren't filler; delay is the very substance of narrative pleasure. When your story sags in the middle, desire has usually gone slack or been resolved too early.","keytakeaway":"Narrative shape = desire awakened (beginning), deferred and complicated (middle), discharged (end). Delay is the substance, not filler.","practice":{"type":"write","prompt":"Take a simple want ('a character wants to apologize to an old friend'). Invent THREE obstacles that would delay the resolution — and make each delay reveal something, not just stall. List them.","rubric":"Treat obstacles as meaningful complications that develop character or stakes, not arbitrary stalls, showing that delay carries the narrative."}},{"track":"Theory","source":"Foucault + Eagleton — synthesis","title":"What your era lets you take for granted","body":"Foucault's 'discourse' and Eagleton's 'ideology' converge on one practical insight: your moment hands you unexamined assumptions — about the self, success, love, work, what's normal — and these seep into your writing invisibly unless you interrogate them.\n\nThe realist assumption that an individual's choices drive their fate; the romantic assumption that love completes a person; the meritocratic assumption that effort earns reward — these aren't universal truths, they're the ideology of a time and place, and they shape your stories by default. Great writing often comes from catching one of these in the act.","keytakeaway":"Your era hands you invisible assumptions that seep into your writing. Catching one in the act is where original work begins.","practice":{"type":"write","prompt":"Name ONE assumption your culture treats as 'just how things are' (about success, love, family, money...) — then describe a story premise that would question it.","rubric":"Identify a genuine cultural assumption (not a strawman) and propose a premise that interrogates rather than merely illustrates it."}}]},{"day":18,"theme":"Keeping the thread: reference","lessons":[{"track":"Sentence","source":"Sentence craft — pronoun reference","title":"Why a fuzzy 'this' or 'it' loses the reader","body":"Every pronoun (it, this, that, they, he, she, which) is a stand-in that points back to a noun — its antecedent. The pronoun has no meaning of its own; it borrows meaning from the noun it refers to. So the entire job of a pronoun depends on the reader instantly knowing which noun it's pointing at.\n\nWHY fuzzy reference breaks reading: when a pronoun could point to two or more nouns, the reader has to STOP and choose — and reading, which should be automatic, becomes a puzzle. 'When Jane met Susan, she was nervous.' Who was nervous? Both are candidates; the reader stalls. The sentence is grammatically fine and communicatively broken.\n\nThe worst offender is the FLOATING 'this' at the start of a sentence, pointing back not to a noun but to a whole vague cloud of previous idea: 'The budget was cut and two people quit. This worried everyone.' This what? The cut? The quitting? Both? WHY it's so common and so damaging: 'this' feels like it's doing its job because YOU know what you mean — but the reader only has the words, and the words left the reference open. The fix is almost always to give 'this' a noun to hold onto: 'This turmoil worried everyone.' Attaching a summarizing noun to a floating 'this' is one of the highest-value edits in all of prose — it instantly tells the reader what the pronoun is gathering up.\n\nThe habit: every time you write it/this/that/they, ask 'exactly which noun does this point to, and is that unmistakable?' If two nouns compete, either repeat the actual noun or restructure so only one candidate is available. Clarity of reference is invisible when you get it right and maddening when you don't.\n\n(Usage note, with the why: 'between you and me,' never 'between you and I' — 'between' is a preposition, and prepositions take the OBJECT form of a pronoun, 'me,' just as you'd say 'between us,' not 'between we.' The 'and I' version is hypercorrection: people learn 'and I' sounds proper and overapply it where the object form is actually required.)","keytakeaway":"A pronoun borrows all its meaning from its antecedent, so the reader must instantly know which noun it points to. Fuzzy reference (esp. a floating 'this') forces the reader to stop and guess. Pin down 'this' by attaching a summarizing noun ('this turmoil'). Prepositions take object pronouns: 'between you and me.'","practice":{"type":"combine","prompt":"Each sentence has a fuzzy or floating reference. Rewrite each so every pronoun points unmistakably to one thing. Do all three.\n\n1. The manager told the employee that he had made a serious mistake. (make it clear the EMPLOYEE erred)\n2. She spent years on the novel and finally abandoned it, which still haunts her. (what haunts her — abandoning it? the years?)\n3. Sales dropped, morale sank, and the founder left. This was the beginning of the end.","rubric":"Each answer should remove ambiguity — by restructuring, repeating the noun, or (for #3) attaching a summarizing noun to 'this' (e.g. 'This collapse was the beginning of the end'). The reader should never have to choose between candidates."}},{"track":"Craft","source":"Shklovsky, On the Theory of Prose","title":"Laying bare the device","body":"Shklovsky celebrated writers who expose their own techniques — 'laying bare the device.' Instead of hiding the machinery of storytelling, some works flaunt it: the narrator who interrupts to discuss how hard this scene is to write, the story that comments on its own conventions.\n\nSterne's Tristram Shandy is his great example. WHY it doesn't break the spell: it replaces one pleasure (immersion) with another (the knowing enjoyment of artifice AS artifice). The choice — hide the seams (illusion) or show them (acknowledged artifice) — is a fundamental stylistic fork. Do you want the reader lost in the dream, or awake to the making?","keytakeaway":"'Laying bare the device' = exposing your own storytelling machinery, trading immersion for the knowing pleasure of artifice. A fork: illusion vs. acknowledged artifice.","practice":{"type":"reflect","prompt":"Which appeals to you more?","options":["Total immersion — hide the seams, sustain the dream","Self-aware artifice — let the reader see the making","Immersion mostly, with rare knowing winks","Not sure yet — I want to try both"],"profileKey":"illusion_vs_artifice"}},{"track":"Theory","source":"Barthes — readerly vs. writerly","title":"Readerly and writerly texts","body":"Barthes distinguished the 'readerly' text (which hands the reader a finished meaning to consume passively) from the 'writerly' text (which makes the reader actively produce meaning, filling gaps, co-creating).\n\nThis connects to Auerbach's 'fraught with background': a text that withholds is inherently more 'writerly' — its gaps demand the reader's participation. WHY withholding empowers the reader: what you leave unsaid, the reader must supply, and what they supply becomes THEIRS — so the text becomes partly their creation. How much you hand over finished vs. make the reader build is a lever you control sentence by sentence, and a signature of your style.","keytakeaway":"Readerly = hands over finished meaning. Writerly = makes the reader co-create. Withholding empowers the reader; how much you hand over is a style signature.","practice":{"type":"reflect","prompt":"Do you want to write 'readerly' (hand over finished meaning) or 'writerly' (make the reader build it) texts?","options":["Readerly — clear, I give the reader the meaning","Writerly — I want the reader to work and co-create","A deliberate mix, controlled moment to moment","Still discovering where I land"],"profileKey":"readerly_vs_writerly"}}]},{"day":19,"theme":"Cutting to strength: concision","lessons":[{"track":"Sentence","source":"Strunk & White + sentence craft — concision","title":"Why needless words dilute force (not just length)","body":"Strunk's most famous rule: 'Omit needless words. Vigorous writing is concise.' But the usual explanation ('shorter is better') misses WHY it works — and shorter isn't always the point.\n\nThe real mechanism: every word in a sentence competes for the reader's attention, and attention is finite. A needless word doesn't just add length — it STEALS emphasis from the words that carry meaning. When you write 'due to the fact that,' those five words draw attention while doing the work of one ('because'), so the reader spends effort on machinery instead of meaning. Cutting deadwood doesn't just shorten the sentence; it CONCENTRATES its force, like reducing a sauce. The strong words, no longer diluted, hit harder.\n\nThis reframes concision as an emphasis tool, not a word-count rule. You cut not to be brief but to make the remaining words matter more.\n\nThe usual deadwood, and why each is empty:\n• 'the fact that' — 'the fact that' almost never adds a fact. 'due to the fact that' → 'because'; 'despite the fact that' → 'although.'\n• Redundant pairs — 'each and every,' 'first and foremost,' 'various different' — the two words mean the same thing; one is free freight.\n• Empty intensifiers — 'very,' 'really,' 'quite,' 'actually' — WHY they backfire: 'very tired' is weaker than 'exhausted' because the intensifier admits the base word wasn't strong enough. Find the stronger word instead.\n• Throat-clearing openers — 'It is important to note that,' 'There is a sense in which' — these delay the actual content; the reader waits through empty throat-clearing for the sentence to start.\n• Nominalizations (yesterday's cousins) — a major source of padding.\n\nThe test for each word: remove it. If the meaning survives, it was needless — and the sentence is now stronger, not just shorter.","keytakeaway":"Needless words don't just lengthen — they steal attention from meaningful words, diluting force. Cutting concentrates the sentence's power, like reducing a sauce. 'Very tired' is weaker than 'exhausted' because the intensifier admits the word was weak. Test: remove it; if meaning survives, it was deadweight.","practice":{"type":"combine","prompt":"Cut each to its concentrated form without losing meaning. Do all four.\n\n1. Due to the fact that it was raining, we made the decision to postpone the event.\n2. It is important to note that each and every student must be present.\n3. She was really very tired and quite exhausted after the long journey.\n4. In the event that there is a situation where you need help, please do not hesitate to reach out.","rubric":"Each answer should remove deadwood (the fact that, redundant pairs, empty intensifiers, throat-clearing) and often replace weak-word-plus-intensifier with one strong word. e.g. 'Because it was raining, we postponed the event.'"}},{"track":"Craft","source":"Peter Brooks, Reading for the Plot","title":"The end that makes the whole readable","body":"Brooks argues that endings are where narrative meaning crystallizes — we read the whole in light of how it ends. The end 'retrospectively' organizes everything: only from the final point can we see what the story was really about, which details mattered.\n\nWHY endings carry such weight: narrative is experienced forward but understood backward — the ending is the vantage from which the shape becomes visible, so a botched ending fails to redeem the reading, leaving the middle's delays meaningless. Good narrative is built backward from its end, seeded so the conclusion feels both surprising and inevitable.","keytakeaway":"The ending retrospectively organizes the whole story's meaning — narrative is lived forward, understood backward. Build toward the end; a botched one wrecks the reading.","practice":{"type":"write","prompt":"Describe an ending IMAGE or moment (not the plot events) for a story — and explain what that ending would make the reader understand about everything before it.","rubric":"Focus on the ending's MEANING and retrospective effect — how it reframes what came before — rather than just describing final events."}},{"track":"Theory","source":"Said — representation as power","title":"Representation as power","body":"Said's deeper claim: the power to REPRESENT is itself a form of power. Whoever gets to describe a people — to say what they're like, what they want, what they're capable of — exercises authority over how those people are seen and treated.\n\nWHY this raises the stakes of craft: to write a person or place is to make a claim about them that enters the world and shapes how others see them; for centuries the represented couldn't answer back on equal terms. This isn't 'only write what you are' — it's writing with awareness that representation acts on the world, and that the represented have their own voice you may be speaking over.","keytakeaway":"The power to represent IS power. Writing a person or place makes a claim that acts on the world — write with that awareness.","practice":{"type":"reflect","prompt":"How much does the ethics of representation weigh on you when you write?","options":["Heavily — I think about it constantly","Somewhat — it's one factor among many","Rarely — I follow the story where it goes","It's making me rethink things right now"],"profileKey":"representation_ethics"}}]},{"day":20,"theme":"Punctuation as structural signal","lessons":[{"track":"Sentence","source":"Sentence craft — colon, semicolon, dash","title":"Why each mark signals a different relationship","body":"The 'advanced' punctuation marks aren't decoration or difficulty — each one signals a specific STRUCTURAL RELATIONSHIP between what comes before and after it. Learn what each one promises the reader and you can use them precisely.\n\nTHE COLON ( : ) — promises 'here it comes.' WHY: a colon says what follows will FULFILL or SPECIFY what preceded it — a list, an explanation, a definition, a punchline. 'She wanted one thing: silence.' The colon raises an expectation and then satisfies it; the reader leans forward at the colon and lands on the payoff. Rule that follows from this: a complete sentence should precede a colon (you can't fulfill a promise you haven't finished making).\n\nTHE SEMICOLON ( ; ) — promises 'these two are equal and linked.' WHY (from Day 9): it joins two INDEPENDENT clauses that are closely related, marking them as balanced peers too connected for a full stop. 'The rain stopped; the streets stayed empty.' A period would sever them; 'and' would subordinate the rhythm; the semicolon holds them as equals in tension. (It also separates list items that themselves contain commas — a 'super-comma' — to prevent confusion about which commas divide what.)\n\nTHE DASH ( — ) — promises 'break, then a twist or emphasis.' WHY: the dash is an interruption, a sharp turn; it inserts a sudden aside or drives to an emphatic finish with more force and surprise than a comma or colon. 'He had one talent — disappearing.' The dash is dramatic where the colon is orderly; it feels like the sentence breaking stride. A pair of dashes sets off a mid-sentence interruption more emphatically than commas would — the reader feels the break.\n\nThe through-line: comma = mild pause within structure; semicolon = two equal clauses linked; colon = setup then fulfillment; dash = dramatic break or twist. Punctuation is not a set of arbitrary rules — it's a signaling system telling the reader how the next chunk relates to the last.","keytakeaway":"Each mark signals a relationship: colon = setup then fulfillment ('one thing: silence'); semicolon = two equal linked clauses; dash = dramatic break or twist. A complete sentence precedes a colon. Punctuation is a signaling system, not arbitrary rules.","practice":{"type":"diagnose","prompt":"Which mark best fits the relationship the sentence needs?","items":[{"sentence":"She finally knew what she wanted ___ to be left alone.","options":["colon ( : )","semicolon ( ; )","comma ( , )"],"answer":0,"explain":"The second part FULFILLS/specifies 'what she wanted' — that's the colon's job: setup then payoff."},{"sentence":"The lecture ran two hours ___ no one left early.","options":["colon ( : )","semicolon ( ; )","comma ( , )"],"answer":1,"explain":"Two complete, closely related independent clauses held as equals — semicolon. (A comma alone would be a splice.)"},{"sentence":"He packed everything he owned ___ two shirts and a book.","options":["colon ( : )","dash ( — )","semicolon ( ; )"],"answer":1,"explain":"The dash gives a dramatic, slightly ironic reveal of how little 'everything' was. (A colon would also be defensible but reads as neutral; the dash adds the twist.)"},{"sentence":"We invited three people ___ Mai, who was late; Jon, who left early; and Sara, who never came.","options":["comma ( , )","colon ( : )","semicolon ( ; )"],"answer":1,"explain":"A colon introduces the list; note the list items are then separated by SEMICOLONS because each item already contains a comma (the semicolon acts as a super-comma)."}]}},{"track":"Craft","source":"Craft — voice consolidation","title":"The writer you're becoming — craft profile","body":"Twenty days in, patterns are emerging in your choices. Across the reflections you've been sorting yourself along real axes: surface vs. depth, texture vs. structure, immersion vs. artifice, sympathy vs. judgment, control vs. openness.\n\nThere's no right answer on any axis — Hemingway and Woolf sit at opposite ends and both are great. WHY knowing your defaults matters: you can then either lean into them (deepening a natural strength) or deliberately work against them (growing a weakness into range). The writers with the most range usually identified their defaults early and then trained the opposite.","keytakeaway":"Knowing your instinctive defaults lets you deepen strengths OR train the opposite for range. Great writers do both, knowingly.","practice":{"type":"reflect","prompt":"On which axis would you most like to build RANGE (grow toward the opposite of your instinct)?","options":["Surface ↔ depth (how much I withhold)","Texture ↔ structure (sentence vs. plot)","Immersion ↔ artifice (hidden vs. visible craft)","Sympathy ↔ judgment (narrative distance)"],"profileKey":"growth_axis"}},{"track":"Theory","source":"Theory — reading like a writer","title":"Reading like a writer","body":"The point of all this theory was never to pass an exam — it was to make you a sharper READER of your own work. You now have questions a naive writer never asks: Am I withholding enough, or over-explaining? Who completes my meaning? What does my form assume about the world? Whose gaze am I writing from? What am I repressing?\n\nWHY this changes everything: these questions turn revision from 'fixing typos' into genuine re-vision — seeing the work again from angles you couldn't access before. Theory's real gift isn't answers; it's better questions.","keytakeaway":"Theory's real gift is better QUESTIONS for revising your own work — turning editing into true re-vision.","practice":{"type":"reflect","prompt":"How has theory most changed your relationship to your own writing so far?","options":["I notice more of what I'm doing unconsciously","I have new questions to ask when revising","I feel more permission to make bold choices","It's still settling — I need more practice"],"profileKey":"theory_impact"}}]},{"day":21,"theme":"Mixing loose and periodic","lessons":[{"track":"Sentence","source":"Sentence craft — loose/periodic in a paragraph","title":"Why a paragraph needs both open and suspended sentences","body":"You've learned the cumulative/loose sentence (core first, relaxed) and the periodic sentence (core last, suspenseful). Real prose doesn't pick one — it MIXES them across a paragraph, and the mix is where paragraph-level rhythm and meaning live.\n\nWHY you need both: an all-loose paragraph flows easily but never builds tension — everything arrives comfortably, nothing is made to matter more. An all-periodic paragraph is exhausting — the reader is held in suspense sentence after sentence with no release, like music that never resolves. The two types do opposite jobs: loose sentences MOVE the reader along (narration, momentum); periodic sentences make the reader WAIT and then land a point hard (emphasis, climax).\n\nThe structural principle: use loose sentences to carry the ordinary forward motion, and save periodic structure for the moment you want to hit. A paragraph of easy loose sentences building momentum, then one periodic sentence that suspends and lands the key point — that's a paragraph with a shape. WHY it works: the loose sentences establish a comfortable rhythm, so when the periodic sentence makes the reader wait, that break in the pattern signals 'this one matters.' You train the reader to relax, then withhold — and the withholding is felt.\n\nThis is the same logic as varying length (Day 13) and end-emphasis (Day 14), now across a whole paragraph: managing where the reader relaxes and where they lean in. The paragraph becomes an instrument for pacing attention.","keytakeaway":"Mix loose sentences (core first, forward motion) with periodic ones (core last, suspense). Loose carries momentum; periodic lands the key point. Build with loose, then let one periodic sentence suspend and hit — the break in rhythm signals importance.","practice":{"type":"combine","prompt":"Write a short paragraph (4-6 sentences) about a small turning point (a decision, a discovery, a goodbye). Use mostly LOOSE sentences to build momentum, then end with ONE PERIODIC sentence that suspends and lands the key emotional point last. Afterward, mark which sentence is the periodic one.","rubric":"Should show a rhythmic build: loose sentences carrying forward motion, then a final periodic sentence delaying its main clause to land the emotional point in the emphatic end position. The student should correctly identify the periodic sentence."}},{"track":"Craft","source":"Chekhov / craft principle — show vs. tell","title":"Show vs. tell — and when telling is right","body":"The most repeated writing advice is 'show, don't tell,' usually traced to Chekhov: don't tell me the moon is shining; show me the glint of light on broken glass.\n\nWHY showing works: a concrete image lets the reader EXPERIENCE and infer the emotion themselves, and an inference the reader draws feels truer than a label handed to them ('she was sad'). Showing recruits the reader's own mind to produce the feeling. BUT telling is a tool, not a sin. WHY you sometimes tell: showing is slow and takes space, so you'd exhaust the reader dramatizing every minor beat. Tell to compress time and skip the unimportant ('Three years passed'); show at the moments that matter. The skill is choosing WHICH moments earn the slow, shown treatment.","keytakeaway":"Show (concrete image → reader infers the feeling) for moments that matter; tell (a label, a summary) to compress time and skip the unimportant. The skill is choosing which moments earn showing.","practice":{"type":"write","prompt":"Take a flat 'told' sentence — 'The reunion was awkward.' — and SHOW it instead in 2-4 sentences, with concrete detail and no emotion-labels. Then write one sentence about the same event that you'd deliberately leave as 'telling' (to skip past it), and note why.","rubric":"The 'shown' version should convey awkwardness through concrete, observed detail without naming the emotion; the 'told' version should sensibly compress something less important, with a reason."}},{"track":"Theory","source":"Bakhtin — dialogism","title":"The novel as a clash of voices","body":"Mikhail Bakhtin argued that the novel's defining power is 'heteroglossia' — many-voicedness. Unlike a lyric poem (one voice) or an epic (one authoritative telling), the novel orchestrates MANY competing social voices, dialects, and worldviews, none fully silenced by the author.\n\nWHY this matters: a rich novel isn't the author's single viewpoint dressed as characters — it's a genuine argument among voices, where even people the author disagrees with get to speak convincingly. The prose carries multiple registers: a narrator's diction rubbing against a character's slang. A 'monologic' work (all one voice, dissent flattened) feels thin; a 'dialogic' one feels alive because reality itself is many-voiced.","keytakeaway":"Bakhtin's 'heteroglossia' — the novel orchestrates many competing voices, none silenced. Dialogic writing (real argument among voices) feels alive; monologic (one flattening voice) feels thin.","practice":{"type":"reflect","prompt":"In your writing, do voices other than your own get to speak convincingly?","options":["Yes — I love writing people I disagree with","Somewhat — but my view tends to win","Rarely — my narrator's voice dominates","I hadn't thought about voice-clash this way"],"profileKey":"dialogism"}}]},{"day":22,"theme":"Varying how sentences begin","lessons":[{"track":"Sentence","source":"Sentence craft — sentence openings","title":"Why starting every sentence the same way fatigues the reader","body":"Most untrained prose starts nearly every sentence with the subject. 'I woke up. I made coffee. I checked my phone. I felt anxious.' Subject-verb, subject-verb, subject-verb.\n\nWHY this fatigues: the OPENING of each sentence is the second-strongest position (after the end — Day 14), and it's the first thing the reader's eye hits each time. When every opening is identical, the eye lands on the same shape over and over, and the prose acquires a monotonous, list-like drone — the tune-out effect of uniform length (Day 13), now at the level of sentence starts. It also signals a writer on autopilot.\n\nThe fix — vary the opening, and each option does expressive work:\n• Adverb/adverbial: 'By noon, I'd given up.' — sets time/manner/condition first.\n• Prepositional phrase: 'In the kitchen, the coffee was cold.' — establishes place/frame.\n• Subordinate clause (left-branching, Day 6): 'Because I couldn't sleep, I made coffee at four.' — supplies cause/context first.\n• -ing or -ed phrase: 'Checking my phone, I felt the anxiety return.' — but WATCH the dangler (Day 12): the phrase must grab the subject that follows.\n• Fronted object (Day 14): 'Coffee I could manage; conversation I could not.'\n\nThe habit: scan the LEFT MARGIN of your paragraph. If every sentence starts with 'I' or 'The,' you've found a drone. Vary a few — and choose openings that do expressive work (time, place, cause), not difference for its own sake.","keytakeaway":"Varying sentence openings breaks the drone of subject-first repetition — the opening is the second-strongest position and the eye hits it every time. Open with adverbials, prepositional phrases, subordinate clauses, or -ing/-ed phrases (mind danglers). Scan your left margin for sameness.","practice":{"type":"combine","prompt":"This passage starts every sentence with the subject — a drone. Rewrite it, varying the openings (use at least three different opening types: adverbial, prepositional phrase, subordinate clause, -ing phrase). Keep the meaning.\n\n'I left the house at dawn. I drove for three hours. I arrived at the coast. I parked near the cliffs. I walked to the edge. I finally understood why I had come.'","rubric":"Should vary sentence openings using at least three distinct types (not all subject-first), with the varied openings doing expressive work (time, place, cause) rather than being arbitrary. The final realization should still land with emphasis."}},{"track":"Craft","source":"James Wood — detail and the real","title":"The threshold of the significant detail","body":"Wood returns often to: which details belong? Too few and a scene is abstract; too many and it's clutter that buries the significant ones. He admires the detail that is significant AND slightly resistant — not obviously symbolic, but charged.\n\nWHY over-description fails: every detail you include tells the reader 'notice this,' so a flood of detail dilutes the signal — if everything is emphasized, nothing is. The significant detail works partly BECAUSE the surrounding restraint makes it stand out. Selection is meaning: what you choose to notice, against what you leave out, IS the characterization and the emphasis.","keytakeaway":"Which details belong is a question of signal: every detail says 'notice this,' so a flood dilutes. Restraint makes the significant detail stand out. Selection is meaning.","practice":{"type":"write","prompt":"Describe a person's desk so that the details reveal something true about them — using no more than THREE details, each doing real work. Resist listing everything.","rubric":"Should use very few details, each characterizing, with the restraint making them significant — rather than an exhaustive inventory."}},{"track":"Theory","source":"Reader-response theory (Iser)","title":"The gaps the reader fills","body":"Building on Barthes, reader-response critics like Wolfgang Iser focused on the 'gaps' in a text — the things left unsaid that the reader must fill in. A text is not a complete object; it's a set of instructions and blanks, and reading is the act of filling the blanks to build the work in your mind.\n\nWHY gaps are powerful: the reader is more engaged by what they must supply than by what they're handed — completing a gap makes the meaning partly theirs, so they're invested. Skilled writers plant productive gaps: a motive left implied, a scene that cuts away at the crucial moment. Too few gaps and the reader is passive; too many and they're lost.","keytakeaway":"A text is instructions plus blanks; reading fills the blanks. Readers engage more with what they supply than what they're handed. Plant productive gaps — but not so many the reader is lost.","practice":{"type":"reflect","prompt":"How comfortable are you leaving deliberate GAPS for the reader to fill?","options":["Very — I trust the reader and love implication","Somewhat — I leave a few but explain the key things","Uncomfortable — I want to make sure they get it","I want to try trusting the reader more"],"profileKey":"gaps_comfort"}}]},{"day":23,"theme":"The power of the short sentence","lessons":[{"track":"Sentence","source":"Sentence craft — the short sentence","title":"When and why to go blunt","body":"You've spent weeks learning to build LONGER sentences. Now the counterweight: the deliberate SHORT sentence, and the discipline of knowing when to deploy it.\n\nWHY a short sentence has such force: after longer sentences, a short one breaks the established rhythm, and the ear registers the break as EMPHASIS (Day 13's contrast, weaponized). But more — a short sentence has nowhere to hide. No subordinate clause softening it, no modifier qualifying it, no 'although' hedging. It states one thing, flatly, and stops. That bareness reads as certainty, finality, or shock. 'He was dead.' 'She said no.' 'It was over.' The brevity itself carries conviction — the sentence is as unqualified as the fact.\n\nSo the short sentence is the tool for: the landing after a build, the blunt fact, the turn, the moment you want to feel inarguable. It's the period-heavy counterpart to end-emphasis — instead of driving the key idea to the end of a long sentence, you give it a whole short sentence of its own.\n\nTHE DANGER, and why it's a discipline: if everything is short, you're back to the choppy drone you started with (Day 4's problem), and the emphasis-by-contrast effect vanishes because there's no long rhythm to break. The short sentence only detonates against a background of longer ones. Its power is RATIONED. Spend it on the moments that deserve to feel final, and let longer sentences do the ordinary work around it.\n\nThis is the mature version of the whole track: not 'short good, long bad,' but orchestrating length as a rhythm, with the short sentence as your accent — the downbeat, the place the reader's breath catches.","keytakeaway":"A deliberate short sentence lands with force: it breaks the rhythm (emphasis by contrast) and has nowhere to hide, so its bareness reads as certainty or shock. But its power is rationed — it only detonates against longer sentences. Use it as an accent, not a default.","practice":{"type":"combine","prompt":"Take this over-qualified, hedged passage and rewrite it so the key moment lands in a short, blunt sentence — with longer sentences building to it.\n\n'After thinking it over for what felt like a very long time, and considering all of the various things that might possibly go wrong, she came to the realization that, in the end, she was not going to be able to forgive him for what he had done.'","rubric":"Should build with a longer sentence or two and land the decision in a short, unqualified sentence (e.g. 'She would not forgive him.') that gains force from the contrast — cutting the hedging."}},{"track":"Craft","source":"Peter Brooks — repetition and return","title":"Repetition as meaning, not error","body":"In everyday writing, repetition is a fault to cut. In narrative, deliberate repetition is a source of MEANING — Brooks (drawing on Freud) sees the compulsion to repeat as central to how stories work. A returning scene, phrase, or situation gains significance precisely by recurring.\n\nWHY repetition signifies: the second time we meet something, we read it AGAINST the first — the return creates a comparison, and the difference (or eerie sameness) carries meaning the single instance couldn't. A phrase repeated in a new context is transformed by it. This is Forster's rhythm (Day 9) from the plot side: what returns, changed, tells the reader how far we've come.","keytakeaway":"Deliberate narrative repetition creates meaning: we read the return against the first instance, and the difference signifies. What comes back, changed, measures how far the story has moved.","practice":{"type":"write","prompt":"Write a single line of dialogue or a short image, then write it a second time in a way that shows it would mean something DIFFERENT if it returned later in a story. Explain the shift in meaning.","rubric":"Should show the same line/image recurring with transformed meaning due to changed context — demonstrating repetition-with-difference as a meaning-making device."}},{"track":"Theory","source":"Structuralism (Propp / binary oppositions)","title":"The hidden structures beneath stories","body":"Structuralism (Propp's folktales, Lévi-Strauss's myths) argued that stories share deep underlying STRUCTURES beneath their surface variety. Propp found that hundreds of Russian folktales used the same limited set of 'functions' (the hero leaves home, receives a magical helper) in the same order. Lévi-Strauss saw myths as built on binary oppositions (raw/cooked, nature/culture) the story works to mediate.\n\nWHY this is useful: it reveals the skeleton under the skin — the recurring shapes (quest, return, transgression-and-punishment) and the deep oppositions your story organizes itself around, often without your noticing. Seeing the structure lets you either satisfy it or knowingly subvert it.","keytakeaway":"Structuralism finds shared deep structures beneath stories — recurring functions (Propp) and binary oppositions (Lévi-Strauss). Seeing your story's skeleton lets you satisfy or subvert it deliberately.","practice":{"type":"reflect","prompt":"Does thinking about deep story-structure appeal to you, or feel constraining?","options":["Appealing — I like knowing the underlying shapes","Useful for subverting — I want to break the pattern","Constraining — I'd rather write intuitively","Curious but unsure how I'd use it"],"profileKey":"structure_appeal"}}]},{"day":24,"theme":"Coordination and subordination together","lessons":[{"track":"Sentence","source":"Sentence craft — combining coordination & subordination","title":"Building complex sentences that stay clear","body":"You learned coordination (joining equals, Day 7) and subordination (ranking, Day 8) separately. Real sentences of any sophistication use BOTH at once — and doing that WITHOUT a pile-up is the capstone of sentence construction.\n\n'Although she had trained for months [subordinate], she lost the race [main], and she never competed again [coordinated main].' Three clauses, precisely ranked: one background, two equal main events.\n\nWHY this stays clear when a comma-spliced pile wouldn't: every clause has a MARKED relationship to the others. The subordinator ('although') tells the reader 'this is background'; the coordinator ('and') says 'this is a second equal event.' The reader always knows the RANK of what they're reading. A pile of equal clauses with no markers forces the reader to guess the relationships. Markers do the reader's ranking for them, so complexity doesn't become confusion.\n\nThe technique for building one deliberately:\n1. Find your MAIN point → the main clause (independent, gets the emphasis).\n2. Background, cause, condition, concession → subordinate it (because, although, when, since, if).\n3. A genuine EQUAL to your main point → coordinate it (and, but, or).\n4. Put the main point in the emphatic position (usually the end — Day 14).\n\nWHY this is the payoff of the whole track: almost any tangled thought becomes clear by sorting its parts into ranks — one main, the rest marked as background or equal — rather than dumping them as a comma-joined heap. Complexity isn't the enemy of clarity; UNRANKED complexity is. Ranked complexity is precise thinking made visible.","keytakeaway":"Sophisticated sentences combine subordination (background/cause/condition) and coordination (equal events), staying clear because every clause is MARKED with its rank — the reader always knows what's background vs. main. Sort a tangled thought into ranks instead of dumping it as a comma-joined heap.","practice":{"type":"combine","prompt":"Combine each pile of short clauses into ONE clear complex or compound-complex sentence, ranking the ideas: subordinate the background/cause, coordinate the equals, put the main point in the emphatic end position. Do all three.\n\n1. The funding fell through. The team had worked for two years. They refused to give up. They started over with nothing.\n2. It was raining hard. The game was not cancelled. The fans stayed. The players kept going.\n3. She knew the risks. She signed the contract. Her lawyer advised against it. She trusted her instinct.","rubric":"Each answer should sort the clauses into ranks — subordinating background/cause (although, because, when), coordinating genuine equals (and, but) — into one clear sentence with the main point in an emphatic position, avoiding a comma-spliced heap."}},{"track":"Craft","source":"Craft — scene vs. summary","title":"Scene and summary — the two gears of narrative","body":"Narrative moves in two gears. SCENE renders a moment in real time, moment by moment, with dialogue and detail (slow, immersive). SUMMARY compresses time, telling you what happened over hours or years in a few sentences (fast, efficient).\n\nWHY you need both (and how they relate to show/tell, Day 21): scene is 'showing' extended over a moment; summary is 'telling' extended over time. An all-scene narrative crawls and exhausts; an all-summary one feels like a report you can't get lost in. The rhythm of good narrative is the alternation — summary to cover ground and get you to the important moment, then scene to slow down and let you live inside it. Where you switch to scene tells the reader 'this is what matters.'","keytakeaway":"Scene (real-time, immersive, slow) and summary (compressed, efficient, fast) are narrative's two gears. Summary covers ground; scene slows at what matters. Switching to scene signals importance.","practice":{"type":"write","prompt":"Write a short passage that uses SUMMARY to cover a long stretch of time quickly (a sentence or two), then shifts into SCENE for one specific important moment. Mark where the gear changes.","rubric":"Should clearly compress time in summary, then slow into a rendered scene (real-time detail/dialogue) at a moment that matters, with the shift visible — demonstrating control of pace."}},{"track":"Theory","source":"Genette — narrative time","title":"Order, duration, frequency","body":"Gérard Genette gave precise tools for how narrative handles TIME. Three axes: ORDER (the sequence of telling vs. events — flashbacks, flash-forwards), DURATION (how much text covers how much time — a page for a second, a sentence for a decade), and FREQUENCY (telling once what happened once, or once what happened many times, or many times what happened once).\n\nWHY this precision helps: it turns vague pacing instincts into deliberate choices. 'This section drags' often means the duration is wrong (too much text for too little event); 'this feels rushed' often means the reverse. Naming the axes lets you diagnose and adjust rather than just sensing something's off.","keytakeaway":"Genette's three axes of narrative time — order (telling vs. events), duration (text-time vs. story-time), frequency (how often the telling repeats the event). Naming them turns vague pacing instincts into diagnosable choices.","practice":{"type":"reflect","prompt":"Which aspect of handling TIME in narrative most interests you to experiment with?","options":["Order — flashbacks, non-linear structure","Duration — stretching a moment or compressing years","Frequency — repetition and recurrence","I mostly write straight chronological — want to break out"],"profileKey":"narrative_time"}}]},{"day":25,"theme":"Balance and antithesis","lessons":[{"track":"Sentence","source":"Sentence craft — balanced & antithetical sentences","title":"Why symmetry persuades and sticks","body":"A BALANCED sentence sets two parts in parallel, equal structure: 'To err is human; to forgive, divine.' An ANTITHETICAL sentence uses that balance to stage an OPPOSITION: 'Ask not what your country can do for you; ask what you can do for your country.' The structure is symmetrical; the meaning turns on the contrast between the halves.\n\nWHY balance is so persuasive and memorable — several mechanisms at once:\n• PREDICTED FORM (Day 11's parallelism): the first half sets a pattern, so the second half's matching shape reads frictionlessly and feels 'right,' even inevitable. The symmetry signals order and control, which reads as authority.\n• CONTRAST SHARPENED BY SAMENESS: in antithesis, holding the STRUCTURE identical throws all attention onto what CHANGED. 'What you can do for your country' vs. 'what your country can do for you' — same words, reversed; the identical frame makes the reversal pop. Sameness of form spotlights difference of content.\n• MEMORABILITY: the matched rhythm makes the sentence easy to hold in memory — which is why proverbs and famous lines are so often balanced. The form is a mnemonic.\n\nWHEN to use it: the turn, the thesis, the line you want quoted. It's high-emphasis and formal — overuse sounds pompous and sing-song, so ration it like the short sentence. But at the key moment — a definition, a contrast, a principle — a balanced or antithetical sentence lands with a finish loose prose can't match. It's the sentence as designed object, drawing on parallelism, end-emphasis, and rationed deployment all at once.","keytakeaway":"Balanced sentences set two parts in equal parallel; antithetical ones use that symmetry to stage a contrast. They persuade and stick because matched form reads as authoritative, identical structure spotlights what changed, and the rhythm aids memory. High-emphasis — ration it for the key turn or principle.","practice":{"type":"combine","prompt":"Turn each ordinary statement into a BALANCED or ANTITHETICAL sentence, using symmetrical structure to sharpen the point. Do all three.\n\n1. Some people talk a lot but don't do much.\n2. It's easy to start something and hard to finish it.\n3. Powerful people worry about being remembered; everyone else worries about being noticed.","rubric":"Each answer should use parallel/symmetrical structure to stage the contrast, with matched grammatical halves (e.g. 'They talk much and do little'), ideally putting the turn in the emphatic position."}},{"track":"Craft","source":"Craft — the turn / reversal","title":"Reversal — the engine of the memorable scene","body":"A scene that ends where it began is inert. The most satisfying scenes contain a TURN — a reversal where something shifts: a character learns something that changes everything, power moves from one person to another, an intention flips into its opposite.\n\nWHY the turn satisfies: it converts a scene from a static tableau into an EVENT — something is different at the end than at the start, so the scene has DONE something. This is the scene-level version of Forster's plot (Day 6): causation and change, not just sequence. A test for any scene: what is DIFFERENT by the end? If nothing, the scene may be describing rather than dramatizing.","keytakeaway":"The best scenes contain a TURN — a reversal that leaves something different at the end. The turn makes a scene an event, not a tableau. Test: what has changed by the end?","practice":{"type":"write","prompt":"Sketch a short scene (a few sentences) with a clear TURN — it should start with one situation/power balance/intention and end with it reversed. Name what flips.","rubric":"Should contain a genuine reversal — something meaningfully different at the end (knowledge, power, intention) than the start — rather than a static or merely descriptive scene."}},{"track":"Theory","source":"Deconstruction (Derrida)","title":"How texts undermine themselves","body":"Derrida's deconstruction is often caricatured, but one usable idea: texts frequently CONTAIN the seeds of their own contradiction. A text that insists on one thing often reveals, in its language, an anxiety about the opposite; the binary oppositions it relies on (reason/emotion, speech/writing) turn out to be unstable, each term secretly depending on the one it claims to be superior to.\n\nWHY a writer can use this: it sensitizes you to the tensions inside your own work — the places where what you're SAYING and what your language is DOING pull apart. Often that gap isn't a flaw to fix but the most interesting thing in the piece: where the writing knows more than the writer's stated intention.","keytakeaway":"Deconstruction: texts often undermine their own claims, and their binary oppositions are unstable. The gap between what a text says and what its language does is often its most interesting point.","practice":{"type":"reflect","prompt":"How do you feel about contradiction and instability in your own writing?","options":["I'm drawn to it — tension is where the life is","I tolerate it but tend to resolve it","I try to eliminate it for clarity","New idea — I want to leave more tension in"],"profileKey":"contradiction_comfort"}}]},{"day":26,"theme":"The long sentence, controlled","lessons":[{"track":"Sentence","source":"Sentence craft — the long sentence done safely","title":"How to write a long sentence that doesn't collapse","body":"The long sentence is the summit — capable of effects no short sentence can achieve: sweep, accumulation, the enactment of a continuous experience, the mind in the act of thinking. But it's where writers most often lose control and produce the tangle you started this course fighting. The difference between a great long sentence and a mess is STRUCTURE, and you now have every tool to build one safely.\n\nWHY long sentences collapse: the reader has limited working memory. A long sentence fails when it forces the reader to hold too many things OPEN at once — an unfinished subject waiting for its verb, a stack of nested clauses, a modifier that hasn't yet found what it modifies. The reader runs out of room and the sentence 'piles up.' A long sentence SUCCEEDS when, at every point, the reader has enough resolved to hold the rest comfortably.\n\nThe techniques for safe length, all from this course:\n• PREFER RIGHT-BRANCHING (Day 6): keep the core near the front, then extend rightward with free modifiers (the cumulative sentence, Day 4). The reader gets the core early and hangs everything after it onto a stable anchor. This is the single most important principle: sentences that grow to the RIGHT stay readable almost indefinitely; sentences that nest and interrupt collapse quickly.\n• AVOID DEEP NESTING: a clause inside a clause inside a clause forces the reader to hold multiple things open. Flatten nesting into sequence.\n• USE PARALLELISM (Day 11) to organize length: repeated parallel structures are a handrail — the pattern tells the reader what's coming.\n• PUNCTUATE THE JOINTS (Day 20): semicolons and colons build a long sentence out of clearly-marked segments, taken in manageable pieces.\n• LAND ON THE EMPHATIC END (Day 14): a long sentence should arrive somewhere — resolve on its most important element, so the length feels like a build to a destination, not a ramble.\n\nWHY this is the fitting near-final lesson: a controlled long sentence uses EVERYTHING — core, branching, cumulative extension, parallelism, punctuation, end-emphasis — in concert. If you can write one a reader glides through without getting lost, you've integrated the whole track.","keytakeaway":"Long sentences collapse when they force the reader to hold too much OPEN (unfinished subjects, nested clauses); they succeed when each point is resolved enough to carry the rest. Keys: right-branch (core early, extend right), avoid deep nesting, use parallelism as a handrail, punctuate the joints, land on the emphatic end.","practice":{"type":"combine","prompt":"Write ONE long sentence (40+ words) that stays perfectly clear — a reader should glide through without getting lost. Build it by right-branching from a strong core, using parallel structures and/or punctuated segments, landing on an emphatic final element. Suggested subject: a place you know intensely, or a single sustained action. Afterward, note which techniques kept it under control.","rubric":"Should be a genuinely long sentence that stays clear, built primarily by right-branching/cumulative extension from an early core (not deep nesting), possibly using parallelism and semicolons/colons, resolving on an emphatic final element. The student should identify the control techniques used."}},{"track":"Craft","source":"Craft — voice and its sources","title":"Where voice actually comes from","body":"'Voice' sounds mystical, but it's built from concrete, analyzable choices you've been studying: sentence length and rhythm, level of diction (plain vs. ornate), how much you withhold, narrative distance, characteristic syntax (do you branch right and flow, or nest and qualify?), what you notice, what you find funny or grave.\n\nWHY this demystifies voice: voice isn't a gift you have or lack — it's the ACCUMULATED PATTERN of your recurring choices. It emerges not by chasing it but by making honest, consistent choices until they form a recognizable signature. You've been building the components all along; voice is what they add up to.","keytakeaway":"Voice isn't mystical — it's the accumulated pattern of your recurring concrete choices (rhythm, diction, distance, what you notice). It emerges from consistent honest choices, not from chasing it.","practice":{"type":"write","prompt":"Write a short paragraph (4-6 sentences) on any subject, then analyze YOUR OWN choices in it: sentence length pattern, level of diction, how much you withheld, what you chose to notice. What early signature do you see?","rubric":"The paragraph plus a genuine self-analysis identifying concrete recurring choices (not vague self-assessment) — showing the student can see voice as built from analyzable components."}},{"track":"Theory","source":"Theory — synthesis of the lenses","title":"Bringing the lenses to your own draft","body":"You've collected a dozen critical lenses. The final theoretical skill is applying SEVERAL at once to a single piece — your own. A mature revision reads a draft through multiple questions in sequence: What's withheld vs. explained (Auerbach/Iser)? Who completes the meaning (Barthes)? What does the form assume (Eagleton)? Whose gaze (Said)? What voices are silenced (Bakhtin)? What's repressed (Gilbert & Gubar)? What contradicts itself (Derrida)?\n\nWHY this is the culmination: no single lens sees everything, but together they make visible almost every dimension of a text that unconscious writing leaves unexamined. This is reading like a writer-critic: not to judge, but to SEE your own work fully enough to revise with intent.","keytakeaway":"The culminating theoretical skill is reading your own draft through several lenses at once — no single lens sees everything, but together they surface nearly every dimension unconscious writing leaves unexamined.","practice":{"type":"reflect","prompt":"Which cluster of lenses do you most want as your permanent revision toolkit?","options":["Withholding & gaps (Auerbach, Barthes, Iser)","Power & the social world (Eagleton, Said, Foucault)","Voice & the repressed (Bakhtin, Gilbert & Gubar)","Structure & its instability (Propp, Derrida)"],"profileKey":"revision_toolkit"}}]},{"day":27,"theme":"Concrete vs. abstract diction","lessons":[{"track":"Sentence","source":"Sentence craft — concrete vs. abstract diction","title":"Why concrete words stick and abstractions slide off","body":"Diction is word CHOICE, and the most consequential choice is concrete vs. abstract. A concrete word names something perceptible — you could see, hear, or touch it (rain, knuckle, rust, slam). An abstract word names a concept or category (weather, emotion, deterioration, conflict).\n\nWHY concrete words stick: the mind evolved to process sensory experience, and concrete words trigger it — 'rust' summons an image, a color, maybe a smell, activating perception and memory. Abstract words trigger no image; the mind processes them as pure category and moves on, retaining little. 'The structure showed deterioration' slides off; 'rust bled down the girders' stays, because you SAW it. Concrete language recruits the reader's senses to make the meaning real; abstract language asks the reader to accept a label.\n\nThis is the word-level version of Wood's telling detail (Day 4), Shklovsky's defamiliarization (Day 3), and Strunk's 'prefer the specific' — all: give the reader something to PERCEIVE, not just to note.\n• 'She experienced significant emotional distress' → 'She couldn't stop shaking.'\n• 'The area suffered economic hardship' → 'The mill closed; the diner followed.'\n\nWHEN abstraction is right — it's not banned: you need abstract words to generalize, to state a principle, to move between concrete instances. The failure isn't 'using any abstraction'; it's staying abstract when you could be concrete — narrating in categories ('emotions,' 'situations,' 'issues') instead of instances. The habit: when an abstract noun is doing important work, ask 'what's the concrete instance of this?' — and usually, showing it hits harder.\n\nThe deeper why, tying the track together: readers believe and remember what they can perceive. Every technique you've learned serves getting a real, perceptible experience into the reader's mind — and at the word level, that means reaching for the concrete.","keytakeaway":"Concrete words (rain, rust, slam) trigger the senses and stick; abstract words (weather, deterioration) trigger no image and slide off. Concrete language recruits the reader's perception. Abstraction is for generalizing between instances — the failure is staying abstract when you could show the instance. Ask: what's the concrete instance of this?","practice":{"type":"combine","prompt":"Rewrite each abstract sentence in concrete, perceptible language — replace category-words with instances you could see or hear. Do all four.\n\n1. The neighborhood was characterized by poverty and neglect.\n2. He displayed considerable anxiety before the interview.\n3. Their relationship had deteriorated over the years.\n4. The meal was a disappointing culinary experience.","rubric":"Each answer should replace abstract nouns (poverty, anxiety, deterioration) with concrete, perceptible instances (specific images, actions, sensory detail) — showing rather than labeling."}},{"track":"Craft","source":"Craft — earning the abstract statement","title":"When you CAN name the emotion","body":"'Show don't tell' (Day 21) and 'prefer concrete' (today) might suggest you can NEVER name an emotion or state a theme directly. Not so — but the direct statement has to be EARNED.\n\nWHY earning matters: a bald emotional statement ('she was heartbroken') with no concrete grounding is a label the reader hasn't been given reason to feel. But after you've shown the concrete particulars — after the reader already feels it — a direct naming can land with enormous force, gathering up everything shown into a single clear statement. The concrete work earns the abstract payoff. This is why the most powerful direct lines come at the END of a passage of accumulated detail, not the start: the showing builds the charge; the telling releases it.","keytakeaway":"You CAN name an emotion or state a theme directly — but it must be earned by concrete grounding first. Showing builds the charge; a direct naming afterward releases it. The bald statement fails only when unearned.","practice":{"type":"write","prompt":"Write a short passage that builds through concrete detail and then EARNS one direct emotional or thematic statement at the end. The final naming should feel earned by everything before it.","rubric":"Should ground the passage in concrete detail first, then land a direct emotional/thematic statement at the end that feels earned by (and gathers up) the preceding concrete work."}},{"track":"Theory","source":"Theory — affect and the reader's body","title":"How writing acts on the reader","body":"A newer strand of theory ('affect theory') attends to how texts act on the reader's BODY and feeling, not just their intellect — the chill, the held breath, the tears, the unease. Meaning isn't only cognitive; literature works partly through sensation and mood, effects that precede or bypass interpretation.\n\nWHY this matters: it validates what you may already sense — that the RHYTHM of your sentences, the pacing, the withholding, produce felt bodily effects (tension, release, dread, ease) somewhat independent of content. A periodic sentence creates suspense in the body; a short blunt sentence delivers a jolt; a long flowing one induces absorption. You're not only conveying information — you're conducting the reader's nervous system.","keytakeaway":"Affect theory: texts act on the reader's body and feeling, not just intellect. Sentence rhythm, pacing, and withholding produce felt bodily effects (tension, release, dread) partly independent of content — you conduct the reader's nervous system.","practice":{"type":"reflect","prompt":"How much do you think about the BODILY/felt effect of your writing (tension, calm, dread), versus its meaning?","options":["A lot — I write for feel and rhythm first","Some — meaning leads but I sense rhythm","Rarely — I focus on what it says","This reframes things — I want to write for feel more"],"profileKey":"affect_awareness"}}]},{"day":28,"theme":"Matching shape to feeling: tone","lessons":[{"track":"Sentence","source":"Sentence craft — tone & register","title":"Why sentence SHAPE must match the feeling","body":"Tone is the attitude your writing takes toward its subject and reader; register is its level of formality. Both are carried not just by WHICH words you choose but by the SHAPE of your sentences — and matching shape to feeling is the final integration of everything you've learned.\n\nWHY sentence shape carries tone (the culminating 'why'): every structural choice you've studied produces a felt effect (Day 27's affect), and those effects ADD UP to tone. Same content, different shape, different feeling:\n• Short, clipped sentences → urgency, tension, bluntness, emotional shutdown. 'He left. She stayed. Nothing more was said.' The curtness IS the coldness.\n• Long, flowing cumulative sentences → ease, reflection, immersion, abundance. The unhurried accumulation feels like a mind at leisure.\n• Periodic, suspended sentences → gravity, formality, building intensity. The delay feels weighty.\n• Loose 'and...and...and' coordination → breathlessness, childlike wonder, overwhelm.\n• Fragments → shock, interiority, a mind under pressure.\n\nSo tone is not a coat of paint applied afterward — it EMERGES from structural choices. If your content is grief but your sentences are long and languid, the shape fights the feeling and the tone muddles. If the content is panic but the sentences are calm and balanced, same problem. Matching them is the skill: let the sentence shape ENACT the feeling, so form and content pull together.\n\nThe habit that closes the loop: after drafting an emotional passage, ask 'does the SHAPE of these sentences feel like the feeling?' A tense moment in long serene sentences is a mismatch — chop them short. A tender moment in clipped fragments may need to open into flow. You're no longer just making correct or even clear sentences — you're making sentences whose very structure carries the emotion. That's the whole craft in one move.\n\nRegister note (the why): formality lives in structure too — longer sentences, subordination, nominalization, and Latinate diction read formal; short sentences, coordination, strong verbs, and plain Anglo-Saxon words read informal. Match register to reader and purpose, and keep it consistent, or the tone wobbles.","keytakeaway":"Sentence SHAPE carries tone: short/clipped = urgency or coldness; long/flowing = ease or immersion; periodic = gravity; fragments = shock. Tone emerges from structure, not paint applied after. Match shape to feeling so form enacts content — ask 'does the shape feel like the feeling?'","practice":{"type":"combine","prompt":"Take this neutral content and write it TWICE, using sentence shape to create two opposite tones — same events, opposite feeling, created by STRUCTURE not just word choice.\n\nContent: A person comes home to an empty apartment after their partner has moved out.\n\nVersion A: tense, cold, shut-down (short, clipped sentences/fragments).\nVersion B: reflective, aching, immersive (long, flowing cumulative sentences).\n\nAfterward, note how the STRUCTURE (not just the words) produced each tone.","rubric":"The two versions should create genuinely different tones primarily through sentence STRUCTURE — A short/clipped/fragmented for tension or shutdown, B long/flowing/cumulative for reflection — not merely by swapping emotional vocabulary. The self-note should identify the structural sources."}},{"track":"Craft","source":"Craft — consistency and the deliberate break","title":"Consistency of tone, and breaking it on purpose","body":"A piece establishes a tonal 'contract' with the reader early — this is funny, this is grave, this is intimate — and consistency keeps the reader oriented. An accidental slip (a jokey line in a solemn passage) jars and breaks trust.\n\nBUT the deliberate tonal BREAK is one of the most powerful effects available. WHY it works: because you've established consistency, a sudden shift lands hard — comedy puncturing tragedy, a plain flat line after ornate ones, sudden tenderness in a hard-boiled voice. The reader feels the rupture precisely because the contract was stable. The rule: control tone consistently enough that you CAN break it meaningfully. An accidental break is a flaw; an earned one is a peak.","keytakeaway":"Establish a consistent tonal contract so the reader stays oriented — then a DELIBERATE break lands hard precisely because the contract was stable. Accidental slips are flaws; earned breaks are peaks.","practice":{"type":"write","prompt":"Write a short passage that establishes one clear tone (e.g. light and comic, or grave and tense) — then deliberately BREAKS it once, at the end, for effect. Note what the break does.","rubric":"Should establish a consistent tone and then execute one intentional, effective tonal break that gains its force from the prior consistency — not an accidental wobble."}},{"track":"Theory","source":"Theory — genre as contract","title":"Genre as a set of expectations","body":"Genre isn't just a shelving category — it's a CONTRACT of expectations between writer and reader. A reader opening a mystery, a romance, or a literary novel brings assumptions about what will happen and how, and the text either fulfills, adjusts, or subverts them.\n\nWHY this is a tool, not a cage: genre expectations are a resource — they let you create suspense (the reader knows the shape and waits), satisfaction (fulfilling the promise), or surprise (subverting it knowingly). You can't meaningfully subvert a convention the reader doesn't expect, so knowing the contract is what MAKES surprise possible. Even 'literary fiction' is a genre with conventions (interiority, ambiguity, resistance to neat plot).","keytakeaway":"Genre is a contract of reader expectations, not just a category — a resource for suspense, satisfaction, or knowing subversion. You can only subvert what the reader expects, so knowing the contract makes surprise possible.","practice":{"type":"reflect","prompt":"What's your relationship to genre conventions?","options":["I like working within a genre's pleasures","I like subverting expectations knowingly","I ignore genre and write what comes","I want to understand the contracts better first"],"profileKey":"genre_stance"}}]},{"day":29,"theme":"Revision as re-seeing","lessons":[{"track":"Sentence","source":"Sentence craft — the revision checklist","title":"The diagnostic pass: seeing your own sentences new","body":"Everything converges here: REVISION, the skill that separates people who write from people who write WELL. First drafts get the thought down; revision is where the sentence craft actually happens. And the core difficulty of revision has a name and a why.\n\nWHY revising your own work is hard: you know what you MEANT, so you read your intention onto the page and can't see what the words actually say. Your mind auto-corrects the gaps, supplies the missing antecedent, hears the emphasis you intended even when the structure doesn't deliver it. The reader has none of that; they have only the words. So the central move of revision is ESTRANGING your own text — making it strange enough that you read what's there, not what you meant. (Yes — Shklovsky's defamiliarization, Day 3, turned on your own draft.)\n\nHow to estrange your own writing:\n• READ IT ALOUD (the master technique, Day 15): your ear catches what your intention-blinded eye skims — splices stumble, danglers sound absurd, drones drone, buried points fall flat.\n• LEAVE TIME: come back after hours or days; distance dissolves the memory of your intention.\n• CHANGE THE FONT OR FORMAT: makes it look unfamiliar, defeating the eye's auto-correction.\n\nThen run the diagnostic checklist — the whole course as a procedure:\n1. CORE: one clear subject + verb, or a competing core? (Days 1-2)\n2. AGREEMENT: verb matched to the true subject, not a decoy? (Day 3)\n3. EMPHASIS: key idea in the emphatic END, or buried? (Day 14)\n4. RANKING: equals coordinated, lesser ideas subordinated — or everything strung with 'and'? (Days 7-8)\n5. JOINS: comma splices/run-ons? Right punctuation for the relationship? (Days 9, 20)\n6. MODIFIERS: each grabs the right neighbor? Danglers? 'Only' placed right? (Day 12)\n7. PARALLELISM: series and pairs match in form? (Day 11)\n8. VERBS: active where it should be? Actions buried in nominalizations? (Days 16-17)\n9. CONCISION: any word removable without loss? (Day 19)\n10. CONCRETENESS: abstractions that could be concrete instances? (Day 27)\n11. RHYTHM & TONE: varied lengths, or a drone? Shape match the feeling? (Days 13, 28)\n12. REFERENCE: every pronoun (esp. 'this') pointing unmistakably to one thing? (Day 18)\n\nWHY a checklist rather than 'just revise': it converts a vague, overwhelming task into specific, answerable questions — and catches the errors your intention-blinded reading skips, because each question forces you to check the WORDS against a standard, not against your memory of what you meant.","keytakeaway":"Revision is hard because you read your INTENTION onto the page, not the actual words — so the core move is estranging your text (read aloud, leave time, change the format) until you see what's there. Then run the checklist: core, agreement, emphasis, ranking, joins, modifiers, parallelism, verbs, concision, concreteness, rhythm/tone, reference.","practice":{"type":"combine","prompt":"Write a rough, messy paragraph FAST (3-5 sentences) on any topic — don't self-edit, let it be flawed. Then run the diagnostic checklist on it, listing every issue you find BY NAME (core? emphasis? danglers? nominalizations? drone? fuzzy 'this'?). Then rewrite it clean. Show the messy version, your diagnosis list, and the revision.","rubric":"Should produce a genuinely rough draft, then a specific NAMED diagnosis using checklist categories (not vague 'it was awkward'), then a revision fixing the identified issues. The quality of the DIAGNOSIS matters most — evidence the student can now see their own sentences' problems by name."}},{"track":"Craft","source":"Craft — revision at the structural level","title":"Revising the bones, not just the sentences","body":"Sentence-level revision polishes the prose; STRUCTURAL revision asks harder questions about the whole. The two are different passes, and the structural one comes first in principle — no amount of beautiful sentences saves a scene that shouldn't exist.\n\nThe structural questions, from the craft track: Does this scene contain a TURN — is anything different by the end (Day 25)? Is desire driving it, or has it gone slack (Days 5, 17)? Is the arrangement (syuzhet) the most effective order, or just chronological by default (Day 8)? Am I in the right narrative distance (Day 16)? Should this be scene or summary (Day 24)? WHY structural revision is scarier and more important: it may mean cutting whole passages you labored over — but a flawed structure can't be rescued by line edits, and the willingness to cut at this level separates finished work from polished drafts.","keytakeaway":"Structural revision (does the scene turn? is desire driving it? is the order right? scene or summary?) is a separate, prior pass from sentence polish — beautiful sentences can't save a scene that shouldn't exist.","practice":{"type":"reflect","prompt":"Which kind of revision comes more naturally to you?","options":["Sentence-level polishing — I love the line work","Structural — I readily cut and rearrange whole scenes","Neither yet — revision is my weak spot","I tend to stop before real revision even starts"],"profileKey":"revision_style"}},{"track":"Theory","source":"Theory — the intentional fallacy","title":"Why you can't fully judge your own meaning","body":"Return to where the theory began (Barthes, Day 2), now as a revision principle. The 'intentional fallacy' (Wimsatt & Beardsley) holds that a work's meaning can't be settled by appeal to what the author intended — the text means what it means to readers, regardless of your plans for it.\n\nWHY this is the deepest revision lesson: it's the theoretical root of why you must estrange your own draft. Your intention is not available to the reader and does not count as the meaning; only the words on the page do. So 'but I MEANT it to be clear/moving/ironic' is irrelevant if the words don't deliver it. Revision is the humbling, essential practice of setting your intention aside and asking what the text ACTUALLY does — which is what a reader will experience.","keytakeaway":"The 'intentional fallacy': a work means what it means to readers, not what you intended — your intention isn't available to them, only the words are. This is the theoretical root of why revision requires setting intention aside.","practice":{"type":"reflect","prompt":"How hard is it for you to set aside what you MEANT and read what you actually wrote?","options":["Very hard — I keep reading in my intention","Getting easier with distance/time","I can do it by reading aloud or waiting","This names exactly what I struggle with"],"profileKey":"intention_gap"}}]},{"day":30,"theme":"Your sentence, your style","lessons":[{"track":"Sentence","source":"Sentence craft — synthesis","title":"From rules to instinct: the whole track in your hands","body":"Thirty days ago, sentences tripped you up: correct but choppy, piling up until the point drowned, the important idea in the wrong place. Look at what you can now do — and how each capacity answers one of those exact problems.\n\nYou find the true SUBJECT (the noun the verb grabs, not the one you picture), so clarity starts from solid ground. You build on one CORE and extend it — rightward and relaxed (CUMULATIVE) or suspended for impact (PERIODIC) — which solves 'choppy and can't combine': you can now grow a sentence to any length and keep it clear. You RANK ideas, coordinating equals and subordinating the lesser, which solves 'the point gets buried': the reader always knows what matters most. And you drive the key idea to the EMPHATIC END, which solves 'the important idea lands in the wrong place': you decide where it lands, on purpose.\n\nEverything else refines these: parallelism and appositives to combine cleanly, modifier placement so nothing dangles, active verbs and de-nominalizing to keep the engine running, concision and concreteness so the words hit, punctuation as a signaling system, and length/rhythm/shape so the prose carries feeling. And the whole kit converges in REVISION — estranging your draft and running the checklist until the sentence you meant is the sentence on the page.\n\nWHY it still sometimes feels like a guess: because the trace hasn't been repeated enough yet to sink below conscious effort — and that's fine. Every one of these was once a slow deliberate check; each becomes a glance with reps, the way sounding out c-a-t became reading. The guess-feeling burns off. You don't need more rules now. You need mileage: write, run the checklist, read aloud, repeat. The rules become instinct only on the far side of repetition — and you've built every rule you need to get there.\n\nOne last reframe: the goal was never 'correct' sentences. It was sentences that do what YOU want — that combine when you need flow, that land when you need force, that carry the feeling you mean. Correctness is the floor. Control is the craft. You have the controls now.","keytakeaway":"You now hold the full kit: find the true subject, build on one core, extend (cumulative) or suspend (periodic), rank ideas (coordinate/subordinate), drive the point to the emphatic end, then refine and revise. It still feels effortful because the traces need mileage to become instinct — reps turn rules into glances. Correctness is the floor; control is the craft.","practice":{"type":"combine","prompt":"Final exercise. Write a short passage (6-10 sentences) on a subject that matters to you — anything. Deliberately use at least SIX techniques from the track, then list which ones you used and where. Aim for control, not perfection: sentences that combine when you want flow, land when you want force, and carry the feeling you mean.\n\nSuggested techniques to draw from: cumulative sentence, periodic sentence, subordination for ranking, end-emphasis, a rationed short sentence, varied openings, parallelism, an appositive, active verbs, concrete diction, tone-through-structure.","rubric":"Should be a coherent passage deliberately deploying at least six named techniques from the course, correctly identified — demonstrating integrated control rather than isolated drills. Look for: a clear core in each sentence, deliberate rhythm (varied length), at least one emphatic landing, and prose whose shape suits its feeling. This is the capstone — assess whether the student can now orchestrate the tools together with intent."}},{"track":"Craft","source":"Craft — synthesis","title":"The writer you've become","body":"The craft track gave you two families of tools: the MOMENT (free indirect style, the telling detail, defamiliarization, metaphor, perspectival POV, show-vs-tell, concrete diction) and STRUCTURE (flat/round character, story-vs-plot causality, desire as motor, fabula/syuzhet arrangement, scene-vs-summary, the turn, narrative time, rhythm and recurrence).\n\nYou've felt which family pulls you — and that pull, refined over thirty days, is the beginning of a real style. The final craft truth: mastery isn't using every tool always; it's knowing which tool a given moment needs, and having them ready. You reach for free indirect style when you want intimacy, ironic distance when you want judgment, a turn when a scene has gone static, summary when you must cover ground, a shown detail when a moment must be felt. The tools are now yours to deploy by instinct and intent together.","keytakeaway":"Craft mastery isn't using every tool always — it's knowing which tool a moment needs and having them ready. Your instinctive pull toward MOMENT or STRUCTURE, refined, is the seed of your style.","practice":{"type":"reflect","prompt":"After thirty days, which describes the writer you've found yourself to be?","options":["A texture writer — sentences, voice, the felt moment","A structure writer — plot, shape, the architecture","A both/hybrid writer — moving between them by intent","Still forming — but now with tools and self-knowledge"],"profileKey":"final_identity"}},{"track":"Theory","source":"Theory — synthesis","title":"The questions you now carry","body":"You began theory thinking it might be an academic exercise. It turned out to be a set of QUESTIONS that make you a sharper reader of your own work — and that was the point all along.\n\nYou now carry: What's withheld vs. explained (Auerbach)? Who completes the meaning (Barthes)? What does 'author' even mean here (Foucault)? What conditions made this possible (Woolf)? What does the form assume about power (Eagleton)? Whose gaze (Said)? What's repressed (Gilbert & Gubar)? Whose voices clash (Bakhtin)? What gaps must the reader fill (Iser)? What deep structure underlies it (Propp)? Where does it contradict itself (Derrida)? Does my intention even count (the intentional fallacy)?\n\nWHY this is the true end of the course: these questions turn every future draft into something you can SEE and therefore improve. Theory's gift was never answers — it was the questions that let you revise with open eyes. You'll carry them into everything you write from here.","keytakeaway":"Theory's real gift was a permanent set of questions that make you a sharper reader of your own work — turning every future draft into something you can see, and therefore improve. Not answers: better questions.","practice":{"type":"reflect","prompt":"Thirty days on — how has this course most changed how you write?","options":["I understand WHY the rules work, so I can rederive them","I can control sentences to do what I want","I read my own drafts with real questions now","All of it is still settling — but I have the tools"],"profileKey":"course_impact"}}]}];

